// Auto-migrated from the original static guide HTML. Structural markup
// and code samples are preserved; inline styles, scripts, and the guide's
// own bespoke syntax-highlight token classes were stripped so every guide
// renders through the one shared GuideReader stylesheet.
export const html: string = "<section id=\"es6\">\n<div class=\"section-header\">\n<div class=\"section-num\">01</div>\n<div class=\"section-title-group\">\n<h2>ES6+ <span class=\"tone-tip\">Essentials</span></h2>\n<p>The modern JavaScript features React depends on \u2014 you'll use every single one of these</p>\n</div>\n</div>\n<div class=\"philosophy-card\">\n<p>React is written in modern JavaScript. You don't need to know every JS feature, but <strong>arrow functions, const/let, template literals, destructuring, spread, and modules</strong> are not optional \u2014 they appear in every React file you'll ever write. Master these before touching hooks.</p>\n<div>// The JavaScript React depends on</div>\n</div>\n<div class=\"concept-grid\">\n<div class=\"concept-card\">\n<div class=\"concept-icon tone-tip\"></div>\n<h3>const &amp; let</h3>\n<p>Use <code>const</code> for everything by default. Use <code>let</code> only if you need to reassign. Never use <code>var</code> \u2014 it has function scope and hoisting quirks that cause bugs in React components.</p>\n</div>\n<div class=\"concept-card\">\n<div class=\"concept-icon tone-info\">\u2192</div>\n<h3>Arrow Functions</h3>\n<p>Arrow functions don't have their own <code>this</code>, are concise, and are the standard in React for callbacks, event handlers, and inline JSX functions. <code>const fn = (x) =&gt; x * 2</code></p>\n</div>\n<div class=\"concept-card\">\n<div class=\"concept-icon tone-success\">``</div>\n<h3>Template Literals</h3>\n<p>Backtick strings with embedded expressions. Use for dynamic classNames, error messages, API URLs. <code>`Hello, ${name}!`</code> instead of string concatenation.</p>\n</div>\n<div class=\"concept-card\">\n<div class=\"concept-icon tone-info\">{ }</div>\n<h3>Shorthand Properties</h3>\n<p>When key and variable share the same name: <code>{'{ name, age }'}</code> instead of <code>{'{ name: name, age: age }'}</code>. Ubiquitous in React component props.</p>\n</div>\n<div class=\"concept-card\">\n<div class=\"concept-icon tone-tip\">?</div>\n<h3>Optional Chaining</h3>\n<p><code>user?.profile?.avatar</code> returns <code>undefined</code> instead of throwing if any part is null/undefined. Replaces dozens of nested <code>&amp;&amp;</code> checks in React renders.</p>\n</div>\n<div class=\"concept-card\">\n<div class=\"concept-icon tone-info\">??</div>\n<h3>Nullish Coalescing</h3>\n<p><code>value ?? 'default'</code> \u2014 uses the right side only if the left is <code>null</code> or <code>undefined</code>. Unlike <code>||</code>, it doesn't trigger on <code>0</code>, <code>\"\"</code>, or <code>false</code>.</p>\n</div>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<div class=\"code-dots\"><div class=\"code-dot tone-danger\"></div><div class=\"code-dot tone-tip\"></div><div class=\"code-dot tone-success\"></div></div>\n<span class=\"code-filename\">es6-in-react.jsx</span>\n<span class=\"code-lang\">JSX</span>\n</div>\n<div class=\"code-body\"><pre><span>// \u2500\u2500\u2500 const / let \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span>const</span> <span>MAX_RETRIES</span> = <span>3</span> <span>// never changes \u2192 const</span>\n<span>let</span> <span>retryCount</span> = <span>0</span> <span>// will be reassigned \u2192 let</span>\n\n<span>// \u2500\u2500\u2500 Arrow Functions \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span>// Traditional function (avoid in React)</span>\n<span>function</span> <span>double</span>(x) { <span>return</span> x * <span>2</span> }\n\n<span>// Arrow: implicit return (no braces = return is automatic)</span>\n<span>const</span> <span>double</span> = (x) =&gt; x * <span>2</span>\n<span>const</span> <span>greet</span> = <span>name</span> =&gt; <span>`Hello, ${name}!`</span> <span>// single param: no parens needed</span>\n\n<span>// Arrow returning an object (wrap in parens)</span>\n<span>const</span> <span>makeUser</span> = (<span>name</span>, <span>age</span>) =&gt; ({ <span>name</span>, <span>age</span> })\n\n<span>// \u2500\u2500\u2500 Template Literals \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span>const</span> <span>apiUrl</span> = <span>`https://api.example.com/users/${userId}/posts`</span>\n<span>const</span> <span>className</span> = <span>`btn ${isActive ? <span>'btn--active'</span> : <span>''</span>} ${variant}`</span>\n\n<span>// \u2500\u2500\u2500 Optional Chaining \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span>const</span> <span>avatar</span> = user?.<span>profile</span>?.<span>avatar</span> <span>// undefined if missing, no throw</span>\n<span>const</span> <span>firstTag</span> = post?.<span>tags</span>?.[<span>0</span>] <span>// optional array index</span>\n<span>const</span> <span>name</span> = <span>getUser</span>?.(id)?.<span>name</span> <span>// optional function call</span>\n\n<span>// \u2500\u2500\u2500 Nullish Coalescing \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span>const</span> <span>count</span> = data?.<span>count</span> ?? <span>0</span> <span>// 0 is safe (vs || which would use 0 = falsy)</span>\n<span>const</span> <span>label</span> = props.<span>label</span> ?? <span>'Untitled'</span>\n\n<span>// \u2500\u2500\u2500 Shorthand Properties \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span>const</span> <span>name</span> = <span>'Alice'</span>\n<span>const</span> <span>age</span> = <span>30</span>\n<span>const</span> <span>user</span> = { <span>name</span>, <span>age</span> } <span>// same as { name: name, age: age }</span>\n\n<span>// \u2500\u2500\u2500 Computed Property Names \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span>const</span> <span>field</span> = <span>'email'</span>\n<span>const</span> <span>update</span> = { [<span>field</span>]: <span>'alice@example.com'</span> } <span>// { email: '...' }</span>\n<span>// Used in forms: setState(prev =&gt; ({ ...prev, [e.target.name]: e.target.value }))</span></pre></div>\n</div>\n<div class=\"callout tone-tip\">\n<div class=\"callout-icon\"></div>\n<div class=\"callout-body\">\n<h4>Arrow Functions &amp; <code>this</code></h4>\n<p>Arrow functions inherit <code>this</code> from their enclosing scope rather than binding their own. This is why class component event handlers used to need <code>.bind(this)</code> \u2014 arrow functions solve it. In functional components (the React default today), <code>this</code> is irrelevant \u2014 no binding ever needed.</p>\n</div>\n</div>\n</section>\n<section id=\"destructuring\">\n<div class=\"section-header\">\n<div class=\"section-num\">02</div>\n<div class=\"section-title-group\">\n<h2>Destructuring <span class=\"tone-info\">Deep Dive</span></h2>\n<p>Pulling values out of arrays and objects \u2014 React's most-used syntax after JSX itself</p>\n</div>\n</div>\n<div class=\"callout tone-info\">\n<div class=\"callout-icon\">\u2139</div>\n<div class=\"callout-body\">\n<h4>Why Destructuring Is Everywhere in React</h4>\n<p>Every hook returns destructured values: <code>const [state, setState] = useState()</code>. Every component receives destructured props: <code>function Card({'{ title, onClick }'})</code>. Every API response gets destructured. You cannot write modern React without fluent destructuring.</p>\n</div>\n</div>\n<div class=\"two-col\">\n<div class=\"code-block\">\n<div class=\"code-header\">\n<div class=\"code-dots\"><div class=\"code-dot tone-danger\"></div><div class=\"code-dot tone-tip\"></div><div class=\"code-dot tone-success\"></div></div>\n<span class=\"code-filename\">Object Destructuring</span>\n<span class=\"code-lang\">JS</span>\n</div>\n<div class=\"code-body\"><pre><span>const</span> <span>user</span> = {\n <span>name</span>: <span>'Alice'</span>,\n <span>age</span>: <span>30</span>,\n <span>role</span>: <span>'admin'</span>,\n <span>address</span>: { <span>city</span>: <span>'Paris'</span> }\n}\n\n<span>// Basic</span>\n<span>const</span> { <span>name</span>, <span>age</span> } = user\n\n<span>// Rename while destructuring</span>\n<span>const</span> { <span>name</span>: <span>userName</span> } = user\n\n<span>// Default value</span>\n<span>const</span> { <span>role</span> = <span>'viewer'</span> } = user\n\n<span>// Nested destructuring</span>\n<span>const</span> { <span>address</span>: { <span>city</span> } } = user\n\n<span>// Rename + default</span>\n<span>const</span> { <span>theme</span>: <span>t</span> = <span>'dark'</span> } = user\n\n<span>// Rest collection</span>\n<span>const</span> { <span>name</span>, ...<span>rest</span> } = user\n<span>// rest = { age: 30, role: 'admin', address: {...} }</span>\n\n<span>// In function parameters (most common in React)</span>\n<span>function</span> <span>Card</span>({ <span>title</span>, <span>onClick</span>, <span>disabled</span> = <span>false</span> }) {\n <span>return</span> &lt;<span>button</span> <span>onClick</span>={<span>onClick</span>}\n <span>disabled</span>={<span>disabled</span>}&gt;{<span>title</span>}&lt;/<span>button</span>&gt;\n}</pre></div>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<div class=\"code-dots\"><div class=\"code-dot tone-danger\"></div><div class=\"code-dot tone-tip\"></div><div class=\"code-dot tone-success\"></div></div>\n<span class=\"code-filename\">Array Destructuring</span>\n<span class=\"code-lang\">JS</span>\n</div>\n<div class=\"code-body\"><pre><span>// Basic \u2014 position matters</span>\n<span>const</span> [<span>first</span>, <span>second</span>] = [<span>10</span>, <span>20</span>, <span>30</span>]\n\n<span>// Skip items with commas</span>\n<span>const</span> [<span>first</span>, , <span>third</span>] = [<span>10</span>, <span>20</span>, <span>30</span>]\n\n<span>// Default values</span>\n<span>const</span> [<span>x</span> = <span>0</span>, <span>y</span> = <span>0</span>] = [<span>5</span>]\n<span>// x=5, y=0</span>\n\n<span>// Rest into array</span>\n<span>const</span> [<span>head</span>, ...<span>tail</span>] = [<span>1</span>, <span>2</span>, <span>3</span>, <span>4</span>]\n<span>// head=1, tail=[2,3,4]</span>\n\n<span>// Swap variables (no temp variable!)</span>\n<span>let</span> <span>a</span> = <span>1</span>, <span>b</span> = <span>2</span>\n;[<span>a</span>, <span>b</span>] = [<span>b</span>, <span>a</span>]\n\n<span>// THE most important React pattern:</span>\n<span>const</span> [<span>count</span>, <span>setCount</span>] = <span>useState</span>(<span>0</span>)\n<span>const</span> [<span>user</span>, <span>setUser</span>] = <span>useState</span>(<span>null</span>)\n<span>const</span> [<span>isOpen</span>, <span>setIsOpen</span>] = <span>useState</span>(<span>false</span>)\n<span>const</span> [<span>items</span>, <span>setItems</span>] = <span>useState</span>([])\n\n<span>// Destructure from function return</span>\n<span>const</span> <span>useToggle</span> = () =&gt; {\n <span>const</span> [<span>on</span>, <span>setOn</span>] = <span>useState</span>(<span>false</span>)\n <span>const</span> <span>toggle</span> = () =&gt; <span>setOn</span>(<span>prev</span> =&gt; !<span>prev</span>)\n <span>return</span> [<span>on</span>, <span>toggle</span>] <span>// caller: const [on, toggle] = useToggle()</span>\n}</pre></div>\n</div>\n</div>\n<div class=\"callout tone-danger\">\n<div class=\"callout-icon\"></div>\n<div class=\"callout-body\">\n<h4>Deep Nested Destructuring \u2014 Don't Over-Do It</h4>\n<p>Nesting more than 2 levels deep creates hard-to-read code: <code>const {'{ a: { b: { c } } }'} = obj</code>. Instead, destructure in stages or use optional chaining. Readability wins over cleverness.</p>\n</div>\n</div>\n</section>\n<section id=\"spread-rest\">\n<div class=\"section-header\">\n<div class=\"section-num\">03</div>\n<div class=\"section-title-group\">\n<h2>Spread <span class=\"tone-info\">&amp; Rest</span> Operators</h2>\n<p>The three dots <code>...</code> that power immutable state updates in React</p>\n</div>\n</div>\n<div class=\"mental-model\">\n<h3> Spread vs Rest \u2014 Same Syntax, Opposite Direction</h3>\n<p><strong>Spread</strong> expands an array/object <em>outward</em> into individual elements. <strong>Rest</strong> collects multiple elements <em>inward</em> into a single array/object. Context determines which is which: rest always appears in destructuring or function parameters; spread appears everywhere else.</p>\n<ul>\n<li><strong>Spread in array literal:</strong> <code>[...existing, newItem]</code> \u2014 copies and extends</li>\n<li><strong>Spread in object literal:</strong> <code>{'{ ...existing, key: value }'}</code> \u2014 shallow clone and override</li>\n<li><strong>Rest in destructuring:</strong> <code>const {'{ a, ...rest }'} = obj</code> \u2014 collects remaining</li>\n<li><strong>Rest in function params:</strong> <code>function fn(first, ...args)</code> \u2014 collects extra arguments</li>\n</ul>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<div class=\"code-dots\"><div class=\"code-dot tone-danger\"></div><div class=\"code-dot tone-tip\"></div><div class=\"code-dot tone-success\"></div></div>\n<span class=\"code-filename\">spread-and-rest.js</span>\n<span class=\"code-lang\">JS</span>\n</div>\n<div class=\"code-body\"><pre><span>// \u2500\u2500\u2500 SPREAD OPERATOR \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n\n<span>// Arrays: copy and extend (IMMUTABLE \u2014 React loves this)</span>\n<span>const</span> <span>fruits</span> = [<span>'apple'</span>, <span>'banana'</span>]\n<span>const</span> <span>moreFruits</span> = [...<span>fruits</span>, <span>'cherry'</span>] <span>// append</span>\n<span>const</span> <span>withOrange</span> = [<span>'orange'</span>, ...<span>fruits</span>] <span>// prepend</span>\n<span>const</span> <span>fruitsCopy</span> = [...<span>fruits</span>] <span>// shallow clone</span>\n<span>const</span> <span>merged</span> = [...<span>fruits</span>, ...<span>moreFruits</span>] <span>// merge two arrays</span>\n\n<span>// Objects: copy and override (the foundation of state updates)</span>\n<span>const</span> <span>user</span> = { <span>name</span>: <span>'Alice'</span>, <span>age</span>: <span>30</span>, <span>role</span>: <span>'admin'</span> }\n<span>const</span> <span>updated</span> = { ...<span>user</span>, <span>age</span>: <span>31</span> } <span>// override age, keep rest</span>\n<span>const</span> <span>withEmail</span> = { ...<span>user</span>, <span>email</span>: <span>'a@b.com'</span> } <span>// add new field</span>\n\n<span>// Last spread wins (right-to-left override)</span>\n<span>const</span> <span>merged</span> = { ...<span>defaults</span>, ...<span>userPrefs</span>, ...<span>sessionPrefs</span> }\n\n<span>// Spread in JSX props (pass-through pattern)</span>\n<span>function</span> <span>Button</span>({ <span>variant</span>, ...<span>rest</span> }) {\n <span>return</span> &lt;<span>button</span> <span>className</span>=<span>{`btn btn--${variant}`}</span> {...<span>rest</span>} /&gt;\n}\n<span>// &lt;Button variant=\"primary\" onClick={fn} disabled aria-label=\"Submit\" /&gt;</span>\n<span>// onClick, disabled, aria-label all pass through via ...rest</span>\n\n<span>// \u2500\u2500\u2500 REST OPERATOR \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n\n<span>// Function: collect remaining arguments</span>\n<span>function</span> <span>sum</span>(<span>first</span>, ...<span>others</span>) {\n <span>return</span> <span>first</span> + <span>others</span>.<span>reduce</span>((<span>a</span>, <span>b</span>) =&gt; <span>a</span> + <span>b</span>, <span>0</span>)\n}\n\n<span>// Object destructuring: collect remaining keys</span>\n<span>const</span> { <span>id</span>, <span>createdAt</span>, ...<span>displayProps</span> } = apiResponse\n<span>// Pass displayProps to component, exclude internal fields</span>\n\n<span>// \u2500\u2500\u2500 REACT STATE UPDATE PATTERNS \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span>// Update one field in an object state</span>\n<span>setUser</span>(<span>prev</span> =&gt; ({ ...<span>prev</span>, <span>name</span>: <span>'Bob'</span> }))\n\n<span>// Add item to array state</span>\n<span>setItems</span>(<span>prev</span> =&gt; [...<span>prev</span>, <span>newItem</span>])\n\n<span>// Remove item by index from array state</span>\n<span>setItems</span>(<span>prev</span> =&gt; [...<span>prev</span>.<span>slice</span>(<span>0</span>, <span>i</span>), ...<span>prev</span>.<span>slice</span>(<span>i</span> + <span>1</span>)])\n\n<span>// Update item in array by id</span>\n<span>setItems</span>(<span>prev</span> =&gt; <span>prev</span>.<span>map</span>(<span>item</span> =&gt; <span>item</span>.<span>id</span> === <span>id</span> ? { ...<span>item</span>, <span>done</span>: <span>true</span> } : <span>item</span>))</pre></div>\n</div>\n</section>\n<section id=\"modules\">\n<div class=\"section-header\">\n<div class=\"section-num\">04</div>\n<div class=\"section-title-group\">\n<h2>Modules <span>&amp; Imports</span></h2>\n<p>ES Modules \u2014 every React file is a module. Understand exports and imports to organize your codebase.</p>\n</div>\n</div>\n<div class=\"two-col\">\n<div class=\"code-block\">\n<div class=\"code-header\">\n<div class=\"code-dots\"><div class=\"code-dot tone-danger\"></div><div class=\"code-dot tone-tip\"></div><div class=\"code-dot tone-success\"></div></div>\n<span class=\"code-filename\">Exporting</span>\n<span class=\"code-lang\">JS</span>\n</div>\n<div class=\"code-body\"><pre><span>// Named exports \u2014 multiple per file</span>\n<span>export const</span> <span>add</span> = (<span>a</span>, <span>b</span>) =&gt; <span>a</span> + <span>b</span>\n<span>export const</span> <span>PI</span> = <span>3.14159</span>\n<span>export function</span> <span>formatDate</span>(<span>date</span>) { ... }\n<span>export</span> { <span>helper1</span>, <span>helper2</span> } <span>// batch export</span>\n\n<span>// Default export \u2014 one per file</span>\n<span>export default function</span> <span>MyComponent</span>() { ... }\n<span>// OR:</span>\n<span>const</span> <span>MyComponent</span> = () =&gt; &lt;<span>div</span>&gt;...&lt;/<span>div</span>&gt;\n<span>export default</span> <span>MyComponent</span>\n\n<span>// Re-export (barrel file pattern)</span>\n<span>export</span> { <span>default</span> <span>as</span> <span>Button</span> } <span>from</span> <span>'./Button'</span>\n<span>export</span> { <span>default</span> <span>as</span> <span>Input</span> } <span>from</span> <span>'./Input'</span>\n<span>// Consumer: import { Button, Input } from './ui'</span></pre></div>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<div class=\"code-dots\"><div class=\"code-dot tone-danger\"></div><div class=\"code-dot tone-tip\"></div><div class=\"code-dot tone-success\"></div></div>\n<span class=\"code-filename\">Importing</span>\n<span class=\"code-lang\">JS</span>\n</div>\n<div class=\"code-body\"><pre><span>// Default import (any name you choose)</span>\n<span>import</span> <span>MyComponent</span> <span>from</span> <span>'./MyComponent'</span>\n<span>import</span> <span>React</span> <span>from</span> <span>'react'</span>\n\n<span>// Named imports (must match export name)</span>\n<span>import</span> { <span>useState</span>, <span>useEffect</span> } <span>from</span> <span>'react'</span>\n<span>import</span> { <span>formatDate</span>, <span>PI</span> } <span>from</span> <span>'./utils'</span>\n\n<span>// Rename on import</span>\n<span>import</span> { <span>add</span> <span>as</span> <span>addNumbers</span> } <span>from</span> <span>'./math'</span>\n\n<span>// Both default + named</span>\n<span>import</span> <span>Router</span>, { <span>Route</span>, <span>Link</span> } <span>from</span> <span>'react-router-dom'</span>\n\n<span>// Namespace import (use sparingly)</span>\n<span>import</span> * <span>as</span> <span>utils</span> <span>from</span> <span>'./utils'</span>\n\n<span>// Dynamic import (code splitting!)</span>\n<span>const</span> <span>LazyMap</span> = <span>lazy</span>(() =&gt; <span>import</span>(<span>'./Map'</span>))\n<span>// Only loads Map.js when component is rendered</span>\n\n<span>// Side-effect only import</span>\n<span>import</span> <span>'./styles.css'</span>\n<span>import</span> <span>'./polyfills'</span></pre></div>\n</div>\n</div>\n<div class=\"callout tone-tip\">\n<div class=\"callout-icon\"></div>\n<div class=\"callout-body\">\n<h4>Barrel Files (index.ts Pattern)</h4>\n<p>Create an <code>index.ts</code> in each folder that re-exports everything. Instead of <code>import Button from '../components/ui/Button/Button'</code>, consumers just write <code>import {'{ Button, Input, Modal }'} from '../components/ui'</code>. Keep barrel files flat \u2014 deeply nested barrels can slow bundlers.</p>\n</div>\n</div>\n</section>\n<section id=\"array-methods\">\n<div class=\"section-header\">\n<div class=\"section-num\">05</div>\n<div class=\"section-title-group\">\n<h2>Array <span class=\"tone-info\">Methods</span></h2>\n<p>The functional array methods that power every React list, filter, transform, and search</p>\n</div>\n</div>\n<div class=\"philosophy-card\">\n<p>In React, you <strong>never mutate arrays directly</strong> (no <code>push</code>, <code>splice</code>, <code>sort</code> in place). You always return a new array. Functional array methods \u2014 <code>map</code>, <code>filter</code>, <code>reduce</code>, <code>find</code> \u2014 are your toolbox. They all return new arrays/values without touching the original.</p>\n<div>// Functional over imperative \u2014 the React way</div>\n</div>\n<div class=\"cheat-grid\">\n<div class=\"cheat-card\">\n<div class=\"cheat-card-header\">\n<span class=\"ch-icon\"></span>\n<h4>map() \u2014 Transform Each Item</h4>\n</div>\n<div class=\"code-body\"><pre><span>// Renders a list \u2014 the #1 React pattern</span>\n<span>const</span> <span>doubled</span> = [<span>1</span>,<span>2</span>,<span>3</span>].<span>map</span>(<span>n</span> =&gt; <span>n</span> * <span>2</span>)\n<span>// [2, 4, 6]</span>\n\n<span>// In JSX (ALWAYS add key prop)</span>\n{<span>users</span>.<span>map</span>(<span>user</span> =&gt; (\n &lt;<span>UserCard</span>\n <span>key</span>=<span>{user.id}</span>\n <span>name</span>=<span>{user.name}</span>\n <span>email</span>=<span>{user.email}</span>\n /&gt;\n))}\n\n<span>// With index (only if no stable id)</span>\n{<span>steps</span>.<span>map</span>((<span>step</span>, <span>i</span>) =&gt; (\n &lt;<span>Step</span> <span>key</span>=<span>{i}</span> <span>number</span>=<span>{i + 1}</span>\n <span>text</span>=<span>{step}</span> /&gt;\n))}</pre></div>\n</div>\n<div class=\"cheat-card\">\n<div class=\"cheat-card-header\">\n<span class=\"ch-icon\"></span>\n<h4>filter() \u2014 Keep Matching Items</h4>\n</div>\n<div class=\"code-body\"><pre><span>// Returns items where callback returns true</span>\n<span>const</span> <span>evens</span> = [<span>1</span>,<span>2</span>,<span>3</span>,<span>4</span>].<span>filter</span>(<span>n</span> =&gt; <span>n</span> % <span>2</span> === <span>0</span>)\n<span>// [2, 4]</span>\n\n<span>// Delete from state</span>\n<span>setTodos</span>(<span>prev</span> =&gt;\n <span>prev</span>.<span>filter</span>(<span>t</span> =&gt; <span>t</span>.<span>id</span> !== <span>deletedId</span>)\n)\n\n<span>// Search/filter UI</span>\n<span>const</span> <span>results</span> = <span>products</span>.<span>filter</span>(<span>p</span> =&gt;\n <span>p</span>.<span>name</span>.<span>toLowerCase</span>()\n .<span>includes</span>(<span>searchTerm</span>.<span>toLowerCase</span>())\n)\n\n<span>// Chain filter + map</span>\n<span>const</span> <span>activeNames</span> = <span>users</span>\n .<span>filter</span>(<span>u</span> =&gt; <span>u</span>.<span>isActive</span>)\n .<span>map</span>(<span>u</span> =&gt; <span>u</span>.<span>name</span>)</pre></div>\n</div>\n<div class=\"cheat-card\">\n<div class=\"cheat-card-header\">\n<span class=\"ch-icon\"></span>\n<h4>reduce() \u2014 Aggregate to One Value</h4>\n</div>\n<div class=\"code-body\"><pre><span>// Sum</span>\n<span>const</span> <span>total</span> = [<span>1</span>,<span>2</span>,<span>3</span>].<span>reduce</span>((<span>acc</span>, <span>n</span>) =&gt; <span>acc</span> + <span>n</span>, <span>0</span>)\n\n<span>// Group by property</span>\n<span>const</span> <span>byStatus</span> = <span>tasks</span>.<span>reduce</span>((<span>acc</span>, <span>task</span>) =&gt; {\n <span>const</span> <span>key</span> = <span>task</span>.<span>status</span>\n <span>return</span> { ...<span>acc</span>, [<span>key</span>]: [...(<span>acc</span>[<span>key</span>] ?? []), <span>task</span>] }\n}, {})\n\n<span>// Array \u2192 object lookup map</span>\n<span>const</span> <span>userById</span> = <span>users</span>.<span>reduce</span>((<span>acc</span>, <span>u</span>) =&gt; ({\n ...<span>acc</span>, [<span>u</span>.<span>id</span>]: <span>u</span>\n}), {})\n<span>// userById[42] \u2192 { id: 42, name: 'Alice' }</span>\n\n<span>// Count occurrences</span>\n<span>const</span> <span>counts</span> = <span>words</span>.<span>reduce</span>((<span>acc</span>, <span>w</span>) =&gt; ({\n ...<span>acc</span>, [<span>w</span>]: (<span>acc</span>[<span>w</span>] ?? <span>0</span>) + <span>1</span>\n}), {})</pre></div>\n</div>\n<div class=\"cheat-card\">\n<div class=\"cheat-card-header\">\n<span class=\"ch-icon\"></span>\n<h4>find / findIndex / some / every</h4>\n</div>\n<div class=\"code-body\"><pre><span>// find \u2014 first match or undefined</span>\n<span>const</span> <span>user</span> = <span>users</span>.<span>find</span>(<span>u</span> =&gt; <span>u</span>.<span>id</span> === <span>targetId</span>)\n\n<span>// findIndex \u2014 index or -1</span>\n<span>const</span> <span>idx</span> = <span>items</span>.<span>findIndex</span>(<span>i</span> =&gt; <span>i</span>.<span>id</span> === <span>id</span>)\n\n<span>// some \u2014 any match? (boolean)</span>\n<span>const</span> <span>hasAdmin</span> = <span>users</span>.<span>some</span>(<span>u</span> =&gt; <span>u</span>.<span>role</span> === <span>'admin'</span>)\n\n<span>// every \u2014 all match? (boolean)</span>\n<span>const</span> <span>allDone</span> = <span>todos</span>.<span>every</span>(<span>t</span> =&gt; <span>t</span>.<span>done</span>)\n\n<span>// includes \u2014 simple value check</span>\n<span>const</span> <span>allowed</span> = [<span>'admin'</span>, <span>'mod'</span>].<span>includes</span>(<span>user</span>.<span>role</span>)\n\n<span>// flat / flatMap</span>\n<span>const</span> <span>flat</span> = [[<span>1</span>,<span>2</span>],[<span>3</span>,<span>4</span>]].<span>flat</span>() <span>// [1,2,3,4]</span>\n<span>const</span> <span>fmap</span> = <span>categories</span>.<span>flatMap</span>(<span>c</span> =&gt; <span>c</span>.<span>items</span>)</pre></div>\n</div>\n<div class=\"cheat-card\">\n<div class=\"cheat-card-header\">\n<span class=\"ch-icon\"></span>\n<h4>sort() \u2014 Always Copy First!</h4>\n</div>\n<div class=\"code-body\"><pre><span>// sort() MUTATES in place \u2014 BAD in React:</span>\n<span>items</span>.<span>sort</span>() <span>// mutates original array!</span>\n\n<span>// Always spread-copy first:</span>\n<span>const</span> <span>sorted</span> = [...<span>items</span>].<span>sort</span>((<span>a</span>, <span>b</span>) =&gt;\n <span>a</span>.<span>name</span>.<span>localeCompare</span>(<span>b</span>.<span>name</span>)\n)\n\n<span>// Numbers: explicit comparator required</span>\n<span>const</span> <span>asc</span> = [...<span>nums</span>].<span>sort</span>((<span>a</span>, <span>b</span>) =&gt; <span>a</span> - <span>b</span>)\n<span>const</span> <span>desc</span> = [...<span>nums</span>].<span>sort</span>((<span>a</span>, <span>b</span>) =&gt; <span>b</span> - <span>a</span>)\n\n<span>// Multi-field sort</span>\n<span>const</span> <span>sorted</span> = [...<span>users</span>].<span>sort</span>((<span>a</span>, <span>b</span>) =&gt;\n <span>a</span>.<span>lastName</span>.<span>localeCompare</span>(<span>b</span>.<span>lastName</span>) ||\n <span>a</span>.<span>firstName</span>.<span>localeCompare</span>(<span>b</span>.<span>firstName</span>)\n)\n\n<span>// toSorted() \u2014 ES2023, non-mutating built-in</span>\n<span>const</span> <span>sorted</span> = <span>items</span>.<span>toSorted</span>((<span>a</span>, <span>b</span>) =&gt; <span>a</span>.<span>id</span> - <span>b</span>.<span>id</span>)</pre></div>\n</div>\n<div class=\"cheat-card\">\n<div class=\"cheat-card-header\">\n<span class=\"ch-icon\"></span>\n<h4>forEach / Array.from / Set Tricks</h4>\n</div>\n<div class=\"code-body\"><pre><span>// forEach \u2014 side effects only, returns undefined</span>\n<span>items</span>.<span>forEach</span>(<span>item</span> =&gt; <span>console</span>.<span>log</span>(<span>item</span>))\n<span>// Use map() when you need a new array</span>\n\n<span>// Array.from \u2014 create from iterable or length</span>\n<span>Array</span>.<span>from</span>({ <span>length</span>: <span>5</span> }, (<span>_</span>, <span>i</span>) =&gt; <span>i</span> + <span>1</span>) <span>// [1,2,3,4,5]</span>\n<span>Array</span>.<span>from</span>(<span>new</span> <span>Set</span>(<span>items</span>)) <span>// deduplicate</span>\n<span>Array</span>.<span>from</span>(<span>nodeList</span>) <span>// NodeList \u2192 Array</span>\n\n<span>// Deduplicate primitives</span>\n<span>const</span> <span>unique</span> = [...<span>new</span> <span>Set</span>(<span>array</span>)]\n\n<span>// Deduplicate objects by field</span>\n<span>const</span> <span>unique</span> = [...<span>new</span> <span>Map</span>(\n <span>items</span>.<span>map</span>(<span>item</span> =&gt; [<span>item</span>.<span>id</span>, <span>item</span>])\n).<span>values</span>()]</pre></div>\n</div>\n</div>\n</section>\n<section id=\"object-methods\">\n<div class=\"section-header\">\n<div class=\"section-num\">06</div>\n<div class=\"section-title-group\">\n<h2>Object <span>Methods</span></h2>\n<p>The built-in Object utilities for iterating, transforming, and merging objects in React</p>\n</div>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<div class=\"code-dots\"><div class=\"code-dot tone-danger\"></div><div class=\"code-dot tone-tip\"></div><div class=\"code-dot tone-success\"></div></div>\n<span class=\"code-filename\">object-methods.js</span>\n<span class=\"code-lang\">JS</span>\n</div>\n<div class=\"code-body\"><pre><span>const</span> <span>config</span> = { <span>theme</span>: <span>'dark'</span>, <span>lang</span>: <span>'en'</span>, <span>fontSize</span>: <span>16</span> }\n\n<span>// \u2500\u2500\u2500 ITERATION \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span>Object</span>.<span>keys</span>(<span>config</span>) <span>// ['theme', 'lang', 'fontSize']</span>\n<span>Object</span>.<span>values</span>(<span>config</span>) <span>// ['dark', 'en', 16]</span>\n<span>Object</span>.<span>entries</span>(<span>config</span>) <span>// [['theme','dark'], ['lang','en'], ['fontSize',16]]</span>\n\n<span>// Render object entries as JSX</span>\n{<span>Object</span>.<span>entries</span>(<span>config</span>).<span>map</span>(([<span>key</span>, <span>value</span>]) =&gt; (\n &lt;<span>ConfigRow</span> <span>key</span>=<span>{key}</span> <span>label</span>=<span>{key}</span> <span>value</span>=<span>{value}</span> /&gt;\n))}\n\n<span>// \u2500\u2500\u2500 MERGING \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span>// Object.assign \u2014 mutates target (use spread instead in React)</span>\n<span>const</span> <span>merged</span> = <span>Object</span>.<span>assign</span>({}, <span>defaults</span>, <span>overrides</span>)\n\n<span>// Prefer spread (cleaner, no mutation risk)</span>\n<span>const</span> <span>merged</span> = { ...<span>defaults</span>, ...<span>overrides</span> }\n\n<span>// \u2500\u2500\u2500 TRANSFORMING \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span>// Object.fromEntries \u2014 entries array back to object</span>\n<span>const</span> <span>uppercased</span> = <span>Object</span>.<span>fromEntries</span>(\n <span>Object</span>.<span>entries</span>(<span>config</span>).<span>map</span>(([<span>k</span>, <span>v</span>]) =&gt; [<span>k</span>, <span>String</span>(<span>v</span>).<span>toUpperCase</span>()])\n)\n\n<span>// Filter object by keys</span>\n<span>const</span> <span>pick</span> = (<span>obj</span>, <span>keys</span>) =&gt;\n <span>Object</span>.<span>fromEntries</span>(<span>keys</span>.<span>map</span>(<span>k</span> =&gt; [<span>k</span>, <span>obj</span>[<span>k</span>]]))\n\n<span>const</span> <span>omit</span> = (<span>obj</span>, <span>keys</span>) =&gt;\n <span>Object</span>.<span>fromEntries</span>(\n <span>Object</span>.<span>entries</span>(<span>obj</span>).<span>filter</span>(([<span>k</span>]) =&gt; !<span>keys</span>.<span>includes</span>(<span>k</span>))\n )\n\n<span>// \u2500\u2500\u2500 INSPECTION \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span>Object</span>.<span>hasOwn</span>(<span>obj</span>, <span>'key'</span>) <span>// modern hasOwnProperty</span>\n<span>Object</span>.<span>isFrozen</span>(<span>obj</span>) <span>// checks if immutable</span>\n<span>Object</span>.<span>freeze</span>(<span>config</span>) <span>// deep constant (dev safety)</span>\n\n<span>// \u2500\u2500\u2500 USEFUL PATTERNS \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span>// Check if object is empty</span>\n<span>const</span> <span>isEmpty</span> = (<span>obj</span>) =&gt; <span>Object</span>.<span>keys</span>(<span>obj</span>).<span>length</span> === <span>0</span>\n\n<span>// Deep clone (JSON-safe values only)</span>\n<span>const</span> <span>clone</span> = <span>JSON</span>.<span>parse</span>(<span>JSON</span>.<span>stringify</span>(<span>obj</span>))\n<span>// For complex objects: structuredClone(obj) \u2190 modern built-in</span></pre></div>\n</div>\n</section>\n<section id=\"string-methods\">\n<div class=\"section-header\">\n<div class=\"section-num\">07</div>\n<div class=\"section-title-group\">\n<h2>String <span class=\"tone-info\">Methods</span></h2>\n<p>String manipulation for display formatting, search, validation, and URL building</p>\n</div>\n</div>\n<div class=\"cheat-grid\">\n<div class=\"cheat-card\">\n<div class=\"cheat-card-header\">\n<span class=\"ch-icon\"></span>\n<h4>Case &amp; Trim</h4>\n</div>\n<div class=\"code-body\"><pre><span>' hello '</span>.<span>trim</span>() <span>// 'hello'</span>\n<span>' hello '</span>.<span>trimStart</span>() <span>// 'hello '</span>\n<span>'hello'</span>.<span>toUpperCase</span>() <span>// 'HELLO'</span>\n<span>'HELLO'</span>.<span>toLowerCase</span>() <span>// 'hello'</span>\n\n<span>// Title case (no built-in)</span>\n<span>const</span> <span>titleCase</span> = <span>s</span> =&gt;\n <span>s</span>.<span>split</span>(<span>' '</span>)\n .<span>map</span>(<span>w</span> =&gt; <span>w</span>[<span>0</span>].<span>toUpperCase</span>() + <span>w</span>.<span>slice</span>(<span>1</span>))\n .<span>join</span>(<span>' '</span>)</pre></div>\n</div>\n<div class=\"cheat-card\">\n<div class=\"cheat-card-header\">\n<span class=\"ch-icon\"></span>\n<h4>Search &amp; Check</h4>\n</div>\n<div class=\"code-body\"><pre><span>'react'</span>.<span>includes</span>(<span>'act'</span>) <span>// true</span>\n<span>'react'</span>.<span>startsWith</span>(<span>'re'</span>) <span>// true</span>\n<span>'react'</span>.<span>endsWith</span>(<span>'ct'</span>) <span>// true</span>\n<span>'react'</span>.<span>indexOf</span>(<span>'a'</span>) <span>// 2</span>\n<span>'react'</span>.<span>lastIndexOf</span>(<span>'r'</span>) <span>// 0</span>\n\n<span>// Search in React filter</span>\n<span>const</span> <span>matches</span> = <span>items</span>.<span>filter</span>(<span>i</span> =&gt;\n <span>i</span>.<span>name</span>.<span>toLowerCase</span>()\n .<span>includes</span>(<span>query</span>.<span>toLowerCase</span>())\n)</pre></div>\n</div>\n<div class=\"cheat-card\">\n<div class=\"cheat-card-header\">\n<span class=\"ch-icon\"></span>\n<h4>Split, Slice &amp; Replace</h4>\n</div>\n<div class=\"code-body\"><pre><span>'a,b,c'</span>.<span>split</span>(<span>','</span>) <span>// ['a','b','c']</span>\n<span>'hello'</span>.<span>slice</span>(<span>1</span>, <span>4</span>) <span>// 'ell'</span>\n<span>'hello'</span>.<span>slice</span>(-<span>3</span>) <span>// 'llo'</span>\n<span>'hi'</span>.<span>repeat</span>(<span>3</span>) <span>// 'hihihi'</span>\n<span>'5'</span>.<span>padStart</span>(<span>3</span>, <span>'0'</span>) <span>// '005'</span>\n<span>'abc'</span>.<span>replace</span>(<span>'a'</span>, <span>'A'</span>) <span>// 'Abc' (first only)</span>\n<span>'aaa'</span>.<span>replaceAll</span>(<span>'a'</span>,<span>'b'</span>) <span>// 'bbb'</span>\n\n<span>// Slug from title</span>\n<span>const</span> <span>toSlug</span> = <span>s</span> =&gt;\n <span>s</span>.<span>toLowerCase</span>().<span>trim</span>()\n .<span>replace</span>(<span>/[^\\w\\s-]/g</span>, <span>''</span>)\n .<span>replace</span>(<span>/\\s+/g</span>, <span>'-'</span>)</pre></div>\n</div>\n<div class=\"cheat-card\">\n<div class=\"cheat-card-header\">\n<span class=\"ch-icon\"></span>\n<h4>Formatting Numbers &amp; Dates</h4>\n</div>\n<div class=\"code-body\"><pre><span>// Number formatting</span>\n(<span>1234.56</span>).<span>toFixed</span>(<span>2</span>) <span>// '1234.56'</span>\n\n<span>new</span> <span>Intl.NumberFormat</span>(<span>'en-US'</span>, {\n <span>style</span>: <span>'currency'</span>, <span>currency</span>: <span>'USD'</span>\n}).<span>format</span>(<span>1234.56</span>)\n<span>// '$1,234.56'</span>\n\n<span>// Date formatting</span>\n<span>new</span> <span>Intl.DateTimeFormat</span>(<span>'en-GB'</span>, {\n <span>day</span>: <span>'numeric'</span>, <span>month</span>: <span>'short'</span>, <span>year</span>: <span>'numeric'</span>\n}).<span>format</span>(<span>new</span> <span>Date</span>())\n<span>// '23 Jun 2024'</span>\n\n<span>// Relative time</span>\n<span>new</span> <span>Intl.RelativeTimeFormat</span>(<span>'en'</span>)\n .<span>format</span>(-<span>3</span>, <span>'day'</span>) <span>// '3 days ago'</span></pre></div>\n</div>\n</div>\n</section>\n<section id=\"conditionals\">\n<div class=\"section-header\">\n<div class=\"section-num\">08</div>\n<div class=\"section-title-group\">\n<h2>Conditionals <span class=\"tone-info\">in JSX</span></h2>\n<p>Every pattern for conditional rendering \u2014 from simple &amp;&amp; to complex multi-branch logic</p>\n</div>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<div class=\"code-dots\"><div class=\"code-dot tone-danger\"></div><div class=\"code-dot tone-tip\"></div><div class=\"code-dot tone-success\"></div></div>\n<span class=\"code-filename\">conditionals-in-jsx.jsx</span>\n<span class=\"code-lang\">JSX</span>\n</div>\n<div class=\"code-body\"><pre><span>// \u2500\u2500\u2500 &amp;&amp; Short-circuit: render if true \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n{<span>isLoggedIn</span> &amp;&amp; &lt;<span>Dashboard</span> /&gt;}\n{<span>error</span> &amp;&amp; &lt;<span>ErrorBanner</span> <span>message</span>=<span>{error}</span> /&gt;}\n\n<span>// TRAP: 0 renders \"0\" in DOM! Use !! or ternary</span>\n{<span>count</span> &amp;&amp; &lt;<span>Badge</span> /&gt;} <span>// if count=0, renders \"0\"</span>\n{<span>count</span> &gt; <span>0</span> &amp;&amp; &lt;<span>Badge</span> /&gt;} <span>// explicit boolean check</span>\n{!!<span>items</span>.<span>length</span> &amp;&amp; &lt;<span>List</span> /&gt;} <span>// coerce to boolean</span>\n\n<span>// \u2500\u2500\u2500 Ternary: render A or B \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n{<span>isLoading</span>\n ? &lt;<span>Spinner</span> /&gt;\n : &lt;<span>Content</span> <span>data</span>=<span>{data}</span> /&gt;\n}\n\n<span>// Ternary for className</span>\n&lt;<span>button</span>\n <span>className</span>=<span>{`btn ${isActive ? 'btn--active' : 'btn--inactive'}`}</span>\n&gt;\n\n<span>// \u2500\u2500\u2500 if/else OUTSIDE JSX (best for complex logic) \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span>function</span> <span>Page</span>() {\n <span>if</span> (<span>isLoading</span>) <span>return</span> &lt;<span>Spinner</span> /&gt; <span>// early return</span>\n <span>if</span> (<span>error</span>) <span>return</span> &lt;<span>Error</span> <span>message</span>=<span>{error}</span> /&gt;\n <span>if</span> (!<span>data</span>) <span>return</span> <span>null</span> <span>// render nothing</span>\n <span>return</span> &lt;<span>Content</span> <span>data</span>=<span>{data}</span> /&gt;\n}\n\n<span>// \u2500\u2500\u2500 Variable assignment (clearest for multi-branch) \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span>let</span> <span>content</span>\n<span>if</span> (<span>status</span> === <span>'loading'</span>) <span>content</span> = &lt;<span>Spinner</span> /&gt;\n<span>else if</span> (<span>status</span> === <span>'error'</span>) <span>content</span> = &lt;<span>Error</span> /&gt;\n<span>else</span> <span>content</span> = &lt;<span>List</span> <span>data</span>=<span>{data}</span> /&gt;\n<span>return</span> &lt;<span>div</span>&gt;{<span>content</span>}&lt;/<span>div</span>&gt;\n\n<span>// \u2500\u2500\u2500 Object map pattern (switch alternative) \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span>const</span> <span>statusComponents</span> = {\n <span>loading</span>: &lt;<span>Spinner</span> /&gt;,\n <span>error</span>: &lt;<span>ErrorMsg</span> /&gt;,\n <span>success</span>: &lt;<span>Content</span> /&gt;,\n <span>empty</span>: &lt;<span>EmptyState</span> /&gt;,\n}\n<span>return</span> <span>statusComponents</span>[<span>status</span>] ?? &lt;<span>Fallback</span> /&gt;\n\n<span>// \u2500\u2500\u2500 Nullish / optional for props \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n&lt;<span>Modal</span>\n <span>title</span>=<span>{title ?? 'Confirm'}</span>\n <span>onClose</span>=<span>{onClose ?? (() =&gt; setOpen(false))}</span>\n/&gt;</pre></div>\n</div>\n<div>\n<div class=\"tip-box\">\n<div class=\"tip-label\"> Do</div>\n<p>Use early returns for loading/error states before main JSX. Keeps the happy path clean and readable.</p>\n</div>\n<div class=\"tip-box tone-tip\">\n<div class=\"tip-label\"> Watch Out</div>\n<p><code>0 &amp;&amp; &lt;X /&gt;</code> renders a literal <code>0</code> in the DOM. Always use an explicit boolean: <code>count &gt; 0 &amp;&amp; &lt;X /&gt;</code>.</p>\n</div>\n<div class=\"tip-box tone-info\">\n<div class=\"tip-label\"> Tip</div>\n<p>Returning <code>null</code> from a component renders nothing and is perfectly valid \u2014 great for permission-guarded UI.</p>\n</div>\n<div class=\"tip-box tone-info\">\n<div class=\"tip-label\"> Pattern</div>\n<p>The object-map pattern scales better than long ternary chains for 3+ states \u2014 one lookup instead of nested logic.</p>\n</div>\n</div>\n</section>\n<section id=\"async\">\n<div class=\"section-header\">\n<div class=\"section-num\">09</div>\n<div class=\"section-title-group\">\n<h2>Async <span class=\"tone-info\">/ Await</span></h2>\n<p>Writing asynchronous code that looks synchronous \u2014 the standard for all React data fetching</p>\n</div>\n</div>\n<div class=\"mental-model\">\n<h3> The Event Loop Mental Model</h3>\n<p>JavaScript is single-threaded. Async operations (network, timers, file I/O) are handed off to the browser's Web APIs. When they complete, their callback enters the <strong>task queue</strong>. The <strong>event loop</strong> picks callbacks off the queue only when the call stack is empty. <code>async/await</code> is syntax sugar over Promises \u2014 it pauses <em>the function</em>, not the thread.</p>\n<ul>\n<li><strong>async function</strong> always returns a Promise, even if you return a plain value</li>\n<li><strong>await</strong> pauses execution inside that function until the Promise resolves</li>\n<li><strong>await</strong> can only be used inside <code>async</code> functions (or at module top-level)</li>\n<li>Multiple <code>await</code>s run sequentially \u2014 use <code>Promise.all</code> for parallelism</li>\n</ul>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<div class=\"code-dots\"><div class=\"code-dot tone-danger\"></div><div class=\"code-dot tone-tip\"></div><div class=\"code-dot tone-success\"></div></div>\n<span class=\"code-filename\">async-patterns.js</span>\n<span class=\"code-lang\">JS</span>\n</div>\n<div class=\"code-body\"><pre><span>// \u2500\u2500\u2500 Basic async/await \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span>async function</span> <span>fetchUser</span>(<span>id</span>) {\n <span>try</span> {\n <span>const</span> <span>response</span> = <span>await</span> <span>fetch</span>(<span>`/api/users/${id}`</span>)\n <span>if</span> (!<span>response</span>.<span>ok</span>) <span>throw new</span> <span>Error</span>(<span>`HTTP ${response.status}`</span>)\n <span>const</span> <span>data</span> = <span>await</span> <span>response</span>.<span>json</span>()\n <span>return</span> <span>data</span>\n } <span>catch</span> (<span>err</span>) {\n <span>console</span>.<span>error</span>(<span>'Failed to fetch user:'</span>, <span>err</span>)\n <span>throw</span> <span>err</span> <span>// re-throw so caller can handle it</span>\n }\n}\n\n<span>// \u2500\u2500\u2500 In React: async inside useEffect \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span>useEffect</span>(() =&gt; {\n <span>// useEffect callback cannot be async \u2014 define inside</span>\n <span>async function</span> <span>load</span>() {\n <span>setLoading</span>(<span>true</span>)\n <span>try</span> {\n <span>const</span> <span>data</span> = <span>await</span> <span>fetchUser</span>(<span>userId</span>)\n <span>setUser</span>(<span>data</span>)\n } <span>catch</span> (<span>err</span>) {\n <span>setError</span>(<span>err</span>.<span>message</span>)\n } <span>finally</span> {\n <span>setLoading</span>(<span>false</span>)\n }\n }\n <span>load</span>()\n}, [<span>userId</span>])\n\n<span>// \u2500\u2500\u2500 Parallel requests (much faster) \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span>const</span> [<span>user</span>, <span>posts</span>, <span>comments</span>] = <span>await</span> <span>Promise</span>.<span>all</span>([\n <span>fetchUser</span>(<span>userId</span>),\n <span>fetchPosts</span>(<span>userId</span>),\n <span>fetchComments</span>(<span>userId</span>),\n])\n<span>// All three run simultaneously \u2192 waits for the slowest one</span>\n\n<span>// \u2500\u2500\u2500 Promise.allSettled \u2014 doesn't fail fast \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span>const</span> <span>results</span> = <span>await</span> <span>Promise</span>.<span>allSettled</span>([\n <span>fetch</span>(<span>'/api/a'</span>), <span>fetch</span>(<span>'/api/b'</span>)\n])\n<span>results</span>.<span>forEach</span>(<span>result</span> =&gt; {\n <span>if</span> (<span>result</span>.<span>status</span> === <span>'fulfilled'</span>) { <span>/* use result.value */</span> }\n <span>else</span> { <span>/* use result.reason */</span> }\n})\n\n<span>// \u2500\u2500\u2500 Promise.race \u2014 first wins \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span>const</span> <span>withTimeout</span> = (<span>promise</span>, <span>ms</span>) =&gt;\n <span>Promise</span>.<span>race</span>([\n <span>promise</span>,\n <span>new</span> <span>Promise</span>((<span>_</span>, <span>reject</span>) =&gt;\n <span>setTimeout</span>(() =&gt; <span>reject</span>(<span>new</span> <span>Error</span>(<span>'Timeout'</span>)), <span>ms</span>)\n )\n ])\n\n<span>// \u2500\u2500\u2500 Async arrow function \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span>const</span> <span>getData</span> = <span>async</span> () =&gt; {\n <span>const</span> <span>res</span> = <span>await</span> <span>fetch</span>(<span>'/api/data'</span>)\n <span>return</span> <span>res</span>.<span>json</span>()\n}</pre></div>\n</div>\n<div class=\"callout tone-danger\">\n<div class=\"callout-icon\"></div>\n<div class=\"callout-body\">\n<h4>Race Condition in useEffect</h4>\n<p>If <code>userId</code> changes while a previous fetch is still in flight, you'll set stale data. Fix with an <strong>abort controller</strong>: create <code>const controller = new AbortController()</code>, pass <code>{'{ signal: controller.signal }'}</code> to fetch, and return <code>() =&gt; controller.abort()</code> as the cleanup function from useEffect.</p>\n</div>\n</div>\n</section>\n<section id=\"promises\">\n<div class=\"section-header\">\n<div class=\"section-num\">10</div>\n<div class=\"section-title-group\">\n<h2>Promises <span class=\"tone-tip\">&amp; Fetch API</span></h2>\n<p>The Fetch API and manual Promise creation \u2014 everything behind the async/await syntax</p>\n</div>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<div class=\"code-dots\"><div class=\"code-dot tone-danger\"></div><div class=\"code-dot tone-tip\"></div><div class=\"code-dot tone-success\"></div></div>\n<span class=\"code-filename\">fetch-api.js</span>\n<span class=\"code-lang\">JS</span>\n</div>\n<div class=\"code-body\"><pre><span>// \u2500\u2500\u2500 Fetch API Basics \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span>// GET</span>\n<span>const</span> <span>res</span> = <span>await</span> <span>fetch</span>(<span>'/api/posts'</span>)\n<span>const</span> <span>posts</span> = <span>await</span> <span>res</span>.<span>json</span>()\n\n<span>// POST with JSON body</span>\n<span>const</span> <span>res</span> = <span>await</span> <span>fetch</span>(<span>'/api/posts'</span>, {\n <span>method</span>: <span>'POST'</span>,\n <span>headers</span>: { <span>'Content-Type'</span>: <span>'application/json'</span>,\n <span>'Authorization'</span>: <span>`Bearer ${token}`</span> },\n <span>body</span>: <span>JSON</span>.<span>stringify</span>({ <span>title</span>: <span>'Hello'</span>, <span>body</span>: <span>'World'</span> })\n})\n\n<span>// \u2500\u2500\u2500 Reusable API client \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span>const</span> <span>apiRequest</span> = <span>async</span> (<span>endpoint</span>, <span>options</span> = {}) =&gt; {\n <span>const</span> <span>token</span> = <span>getAuthToken</span>()\n <span>const</span> <span>response</span> = <span>await</span> <span>fetch</span>(<span>`/api${endpoint}`</span>, {\n <span>headers</span>: {\n <span>'Content-Type'</span>: <span>'application/json'</span>,\n ...<span>token</span> &amp;&amp; { <span>'Authorization'</span>: <span>`Bearer ${token}`</span> },\n ...<span>options</span>.<span>headers</span>,\n },\n ...<span>options</span>,\n })\n <span>if</span> (!<span>response</span>.<span>ok</span>) {\n <span>const</span> <span>error</span> = <span>await</span> <span>response</span>.<span>json</span>().<span>catch</span>(() =&gt; ({}))\n <span>throw new</span> <span>Error</span>(<span>error</span>.<span>message</span> ?? <span>`HTTP ${response.status}`</span>)\n }\n <span>if</span> (<span>response</span>.<span>status</span> === <span>204</span>) <span>return null</span>\n <span>return</span> <span>response</span>.<span>json</span>()\n}\n<span>// Usage: const posts = await apiRequest('/posts')</span>\n\n<span>// \u2500\u2500\u2500 Promise Constructor \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span>const</span> <span>delay</span> = (<span>ms</span>) =&gt; <span>new</span> <span>Promise</span>(<span>resolve</span> =&gt; <span>setTimeout</span>(<span>resolve</span>, <span>ms</span>))\n<span>await</span> <span>delay</span>(<span>500</span>) <span>// pause for 500ms</span>\n\n<span>// Promisify a callback-based function</span>\n<span>const</span> <span>readFileAsync</span> = (<span>path</span>) =&gt;\n <span>new</span> <span>Promise</span>((<span>resolve</span>, <span>reject</span>) =&gt; {\n <span>fs</span>.<span>readFile</span>(<span>path</span>, <span>'utf8'</span>, (<span>err</span>, <span>data</span>) =&gt; {\n <span>if</span> (<span>err</span>) <span>reject</span>(<span>err</span>)\n <span>else</span> <span>resolve</span>(<span>data</span>)\n })\n })\n\n<span>// \u2500\u2500\u2500 Abort fetch (cleanup useEffect) \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span>useEffect</span>(() =&gt; {\n <span>const</span> <span>controller</span> = <span>new</span> <span>AbortController</span>()\n <span>const</span> <span>load</span> = <span>async</span> () =&gt; {\n <span>try</span> {\n <span>const</span> <span>res</span> = <span>await</span> <span>fetch</span>(<span>'/api/data'</span>, { <span>signal</span>: <span>controller</span>.<span>signal</span> })\n <span>setData</span>(<span>await</span> <span>res</span>.<span>json</span>())\n } <span>catch</span> (<span>err</span>) {\n <span>if</span> (<span>err</span>.<span>name</span> !== <span>'AbortError'</span>) <span>setError</span>(<span>err</span>)\n }\n }\n <span>load</span>()\n <span>return</span> () =&gt; <span>controller</span>.<span>abort</span>() <span>// cleanup</span>\n}, [<span>id</span>])</pre></div>\n</div>\n</section>\n<section id=\"events\">\n<div class=\"section-header\">\n<div class=\"section-num\">11</div>\n<div class=\"section-title-group\">\n<h2>Event <span>Handling</span></h2>\n<p>Synthetic events, SyntheticEvent object, event delegation \u2014 how React wraps native browser events</p>\n</div>\n</div>\n<div class=\"callout tone-info\">\n<div class=\"callout-icon\">\u2139</div>\n<div class=\"callout-body\">\n<h4>React's SyntheticEvent</h4>\n<p>React wraps native browser events in a <strong>SyntheticEvent</strong> that normalizes cross-browser differences. It pools events for performance \u2014 <strong>don't store them async</strong> (use <code>e.persist()</code> in legacy code, or just extract the values you need synchronously). React 17+ no longer pools events, so this is less of a concern in modern React.</p>\n</div>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<div class=\"code-dots\"><div class=\"code-dot tone-danger\"></div><div class=\"code-dot tone-tip\"></div><div class=\"code-dot tone-success\"></div></div>\n<span class=\"code-filename\">event-handling.jsx</span>\n<span class=\"code-lang\">JSX</span>\n</div>\n<div class=\"code-body\"><pre><span>// \u2500\u2500\u2500 Basic event handlers \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span>// Always camelCase in JSX (onClick not onclick)</span>\n&lt;<span>button</span> <span>onClick</span>=<span>{handleClick}</span>&gt;Click&lt;/<span>button</span>&gt; <span>// </span>\n&lt;<span>button</span> <span>onClick</span>=<span>{handleClick()}</span>&gt;Click&lt;/<span>button</span>&gt; <span>// calls on render!</span>\n&lt;<span>button</span> <span>onClick</span>=<span>{() =&gt; handleClick()}</span>&gt;Click&lt;/<span>button</span>&gt; <span>// arrow wrapper</span>\n\n<span>// \u2500\u2500\u2500 The SyntheticEvent object \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span>const</span> <span>handleClick</span> = (<span>e</span>) =&gt; {\n <span>e</span>.<span>preventDefault</span>() <span>// stop form submit, link navigate</span>\n <span>e</span>.<span>stopPropagation</span>() <span>// stop bubbling to parent</span>\n <span>console</span>.<span>log</span>(<span>e</span>.<span>target</span>) <span>// element that was clicked</span>\n <span>console</span>.<span>log</span>(<span>e</span>.<span>currentTarget</span>) <span>// element with the handler</span>\n <span>console</span>.<span>log</span>(<span>e</span>.<span>type</span>) <span>// 'click'</span>\n <span>console</span>.<span>log</span>(<span>e</span>.<span>clientX</span>, <span>e</span>.<span>clientY</span>) <span>// mouse position</span>\n}\n\n<span>// \u2500\u2500\u2500 Input events \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span>const</span> <span>handleChange</span> = (<span>e</span>) =&gt; {\n <span>setValue</span>(<span>e</span>.<span>target</span>.<span>value</span>) <span>// text input value</span>\n}\n\n<span>// Controlled input pattern</span>\n&lt;<span>input</span>\n <span>type</span>=<span>\"text\"</span>\n <span>value</span>=<span>{value}</span>\n <span>onChange</span>=<span>{e =&gt; setValue(e.target.value)}</span>\n/&gt;\n\n<span>// Checkbox</span>\n&lt;<span>input</span> <span>type</span>=<span>\"checkbox\"</span>\n <span>checked</span>=<span>{checked}</span>\n <span>onChange</span>=<span>{e =&gt; setChecked(e.target.checked)}</span>\n/&gt;\n\n<span>// Select</span>\n&lt;<span>select</span> <span>value</span>=<span>{selected}</span>\n <span>onChange</span>=<span>{e =&gt; setSelected(e.target.value)}</span>&gt;\n\n<span>// \u2500\u2500\u2500 Generic form handler \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span>const</span> <span>handleInput</span> = (<span>e</span>) =&gt; {\n <span>const</span> { <span>name</span>, <span>value</span>, <span>type</span>, <span>checked</span> } = <span>e</span>.<span>target</span>\n <span>setForm</span>(<span>prev</span> =&gt; ({\n ...<span>prev</span>,\n [<span>name</span>]: <span>type</span> === <span>'checkbox'</span> ? <span>checked</span> : <span>value</span>\n }))\n}\n\n<span>// \u2500\u2500\u2500 Keyboard events \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span>const</span> <span>handleKeyDown</span> = (<span>e</span>) =&gt; {\n <span>if</span> (<span>e</span>.<span>key</span> === <span>'Enter'</span>) <span>submit</span>()\n <span>if</span> (<span>e</span>.<span>key</span> === <span>'Escape'</span>) <span>close</span>()\n <span>if</span> (<span>e</span>.<span>ctrlKey</span> &amp;&amp; <span>e</span>.<span>key</span> === <span>'s'</span>) { <span>e</span>.<span>preventDefault</span>(); <span>save</span>() }\n}\n\n<span>// \u2500\u2500\u2500 Pass extra data to handler \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n{<span>items</span>.<span>map</span>(<span>item</span> =&gt; (\n &lt;<span>button</span>\n <span>key</span>=<span>{item.id}</span>\n <span>onClick</span>=<span>{() =&gt; handleDelete(item.id)}</span>\n &gt;Delete&lt;/<span>button</span>&gt;\n))}</pre></div>\n</div>\n</section>\n<section id=\"timers\">\n<div class=\"section-header\">\n<div class=\"section-num\">12</div>\n<div class=\"section-title-group\">\n<h2>Timers <span class=\"tone-info\">&amp; Intervals</span></h2>\n<p>setTimeout, setInterval, requestAnimationFrame \u2014 and how to clean them up in useEffect</p>\n</div>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<div class=\"code-dots\"><div class=\"code-dot tone-danger\"></div><div class=\"code-dot tone-tip\"></div><div class=\"code-dot tone-success\"></div></div>\n<span class=\"code-filename\">timers-in-react.jsx</span>\n<span class=\"code-lang\">JSX</span>\n</div>\n<div class=\"code-body\"><pre><span>// \u2500\u2500\u2500 setTimeout \u2014 run once after delay \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span>useEffect</span>(() =&gt; {\n <span>const</span> <span>id</span> = <span>setTimeout</span>(() =&gt; {\n <span>setVisible</span>(<span>false</span>) <span>// hide after 3 seconds</span>\n }, <span>3000</span>)\n <span>return</span> () =&gt; <span>clearTimeout</span>(<span>id</span>) <span>// cleanup on unmount!</span>\n}, [])\n\n<span>// \u2500\u2500\u2500 setInterval \u2014 repeat on schedule \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span>useEffect</span>(() =&gt; {\n <span>const</span> <span>id</span> = <span>setInterval</span>(() =&gt; {\n <span>setTick</span>(<span>t</span> =&gt; <span>t</span> + <span>1</span>)\n }, <span>1000</span>)\n <span>return</span> () =&gt; <span>clearInterval</span>(<span>id</span>) <span>// cleanup!</span>\n}, [])\n\n<span>// \u2500\u2500\u2500 Debounce: delay until user stops typing \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span>useEffect</span>(() =&gt; {\n <span>const</span> <span>handler</span> = <span>setTimeout</span>(() =&gt; {\n <span>search</span>(<span>query</span>)\n }, <span>300</span>)\n <span>return</span> () =&gt; <span>clearTimeout</span>(<span>handler</span>) <span>// cancel if query changes</span>\n}, [<span>query</span>])\n\n<span>// \u2500\u2500\u2500 Reusable useDebounce hook \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span>function</span> <span>useDebounce</span>(<span>value</span>, <span>delay</span>) {\n <span>const</span> [<span>debounced</span>, <span>setDebounced</span>] = <span>useState</span>(<span>value</span>)\n <span>useEffect</span>(() =&gt; {\n <span>const</span> <span>t</span> = <span>setTimeout</span>(() =&gt; <span>setDebounced</span>(<span>value</span>), <span>delay</span>)\n <span>return</span> () =&gt; <span>clearTimeout</span>(<span>t</span>)\n }, [<span>value</span>, <span>delay</span>])\n <span>return</span> <span>debounced</span>\n}\n<span>// const debouncedSearch = useDebounce(query, 300)</span>\n\n<span>// \u2500\u2500\u2500 requestAnimationFrame \u2014 smooth animations \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span>useEffect</span>(() =&gt; {\n <span>let</span> <span>rafId</span>\n <span>const</span> <span>animate</span> = () =&gt; {\n <span>setProgress</span>(<span>p</span> =&gt; <span>p</span> + <span>0.01</span>)\n <span>rafId</span> = <span>requestAnimationFrame</span>(<span>animate</span>)\n }\n <span>rafId</span> = <span>requestAnimationFrame</span>(<span>animate</span>)\n <span>return</span> () =&gt; <span>cancelAnimationFrame</span>(<span>rafId</span>)\n}, [])</pre></div>\n</div>\n<div class=\"callout tone-danger\">\n<div class=\"callout-icon\"></div>\n<div class=\"callout-body\">\n<h4>Always Clean Up Timers</h4>\n<p>If you don't return a cleanup function from <code>useEffect</code>, a timer may fire after a component unmounts and try to call <code>setState</code> on an unmounted component \u2014 causing memory leaks and React warnings. Every <code>setTimeout</code> and <code>setInterval</code> in an effect needs a paired <code>clearTimeout</code> / <code>clearInterval</code> in the cleanup.</p>\n</div>\n</div>\n</section>\n<section id=\"closures\">\n<div class=\"section-header\">\n<div class=\"section-num\">13</div>\n<div class=\"section-title-group\">\n<h2>Closures <span class=\"tone-info\">&amp; Scope</span></h2>\n<p>The most important concept in JavaScript \u2014 and the root cause of most React hook bugs</p>\n</div>\n</div>\n<div class=\"philosophy-card\">\n<p>A <strong>closure</strong> is a function that \"remembers\" the variables from the scope where it was created, even after that scope has finished executing. Every React hook, every event handler, every callback you write is a closure. Understanding closures is understanding why stale state bugs happen in hooks.</p>\n<div>// \"Closures are functions that carry their backpack of variables wherever they go\" \u2014 Kyle Simpson</div>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<div class=\"code-dots\"><div class=\"code-dot tone-danger\"></div><div class=\"code-dot tone-tip\"></div><div class=\"code-dot tone-success\"></div></div>\n<span class=\"code-filename\">closures-and-hooks.js</span>\n<span class=\"code-lang\">JS</span>\n</div>\n<div class=\"code-body\"><pre><span>// \u2500\u2500\u2500 What is a closure? \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span>function</span> <span>makeCounter</span>() {\n <span>let</span> <span>count</span> = <span>0</span> <span>// private variable</span>\n <span>return</span> {\n <span>increment</span>: () =&gt; ++<span>count</span>, <span>// closes over count</span>\n <span>get</span>: () =&gt; <span>count</span>\n }\n}\n<span>const</span> <span>counter</span> = <span>makeCounter</span>()\n<span>counter</span>.<span>increment</span>() <span>// count = 1</span>\n<span>counter</span>.<span>get</span>() <span>// 1</span>\n\n<span>// \u2500\u2500\u2500 Stale closure in useEffect \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span>function</span> <span>Counter</span>() {\n <span>const</span> [<span>count</span>, <span>setCount</span>] = <span>useState</span>(<span>0</span>)\n\n <span>useEffect</span>(() =&gt; {\n <span>const</span> <span>id</span> = <span>setInterval</span>(() =&gt; {\n <span>setCount</span>(<span>count</span> + <span>1</span>) <span>// STALE! count is always 0</span>\n }, <span>1000</span>)\n <span>return</span> () =&gt; <span>clearInterval</span>(<span>id</span>)\n }, []) <span>// [] means effect runs once, capturing count=0 forever</span>\n\n <span>// Fix: functional update (doesn't need current value from closure)</span>\n <span>useEffect</span>(() =&gt; {\n <span>const</span> <span>id</span> = <span>setInterval</span>(() =&gt; {\n <span>setCount</span>(<span>prev</span> =&gt; <span>prev</span> + <span>1</span>) <span>// always reads fresh state</span>\n }, <span>1000</span>)\n <span>return</span> () =&gt; <span>clearInterval</span>(<span>id</span>)\n }, [])\n}\n\n<span>// \u2500\u2500\u2500 Closure for private state (module pattern) \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span>const</span> <span>authService</span> = (() =&gt; {\n <span>let</span> <span>_token</span> = <span>null</span> <span>// private, no external access</span>\n <span>return</span> {\n <span>setToken</span>: (<span>t</span>) =&gt; { <span>_token</span> = <span>t</span> },\n <span>getToken</span>: () =&gt; <span>_token</span>,\n <span>isLoggedIn</span>: () =&gt; <span>_token</span> !== <span>null</span>\n }\n})()\n\n<span>// \u2500\u2500\u2500 Scope chain (let / const vs var) \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span>for</span> (<span>var</span> <span>i</span> = <span>0</span>; <span>i</span> &lt; <span>3</span>; <span>i</span>++) {\n <span>setTimeout</span>(() =&gt; <span>console</span>.<span>log</span>(<span>i</span>)) <span>// prints 3,3,3 (var leaks)</span>\n}\n\n<span>for</span> (<span>let</span> <span>i</span> = <span>0</span>; <span>i</span> &lt; <span>3</span>; <span>i</span>++) {\n <span>setTimeout</span>(() =&gt; <span>console</span>.<span>log</span>(<span>i</span>)) <span>// prints 0,1,2 (let per iteration)</span>\n}</pre></div>\n</div>\n<div>\n<div class=\"tip-box tone-danger\">\n<div class=\"tip-label\"> Stale Closure</div>\n<p>A closure captures the variable <em>reference</em> at creation time. If the effect dependency array is empty <code>[]</code>, the closure captures the initial value and never updates.</p>\n</div>\n<div class=\"tip-box tone-info\">\n<div class=\"tip-label\"> Functional Updates</div>\n<p>When new state depends on old state, use <code>setState(prev =&gt; prev + 1)</code>. React passes the fresh value \u2014 no closure bug possible.</p>\n</div>\n<div class=\"tip-box tone-info\">\n<div class=\"tip-label\"> useRef Escape Hatch</div>\n<p><code>const countRef = useRef(count); countRef.current = count</code> \u2014 a ref gives you always-fresh access from inside stale closures.</p>\n</div>\n<div class=\"tip-box tone-tip\">\n<div class=\"tip-label\"> Dependency Arrays</div>\n<p>The ESLint rule <code>react-hooks/exhaustive-deps</code> catches stale closure bugs automatically. Always trust it and add missing dependencies.</p>\n</div>\n</div>\n</section>\n<section id=\"classes\">\n<div class=\"section-header\">\n<div class=\"section-num\">14</div>\n<div class=\"section-title-group\">\n<h2>Classes <span class=\"tone-tip\">&amp; OOP in React</span></h2>\n<p>ES6 classes \u2014 their role in modern React, when to use them, and key patterns</p>\n</div>\n</div>\n<div class=\"callout tone-info\">\n<div class=\"callout-icon\">\u2139</div>\n<div class=\"callout-body\">\n<h4>Class Components vs Functional Components</h4>\n<p>Class components were the original React pattern. Since React 16.8 (hooks), <strong>functional components are the standard</strong>. You'll encounter class components in legacy codebases. The one place where classes are still required: <strong>Error Boundaries</strong> (React has no hook for <code>componentDidCatch</code> yet).</p>\n</div>\n</div>\n<div class=\"two-col\">\n<div class=\"code-block\">\n<div class=\"code-header\">\n<div class=\"code-dots\"><div class=\"code-dot tone-danger\"></div><div class=\"code-dot tone-tip\"></div><div class=\"code-dot tone-success\"></div></div>\n<span class=\"code-filename\">Class Component (legacy)</span>\n<span class=\"code-lang\">JSX</span>\n</div>\n<div class=\"code-body\"><pre><span>class</span> <span>Counter</span> <span>extends</span> <span>React.Component</span> {\n <span>// Class field syntax (modern)</span>\n <span>state</span> = { <span>count</span>: <span>0</span> }\n\n <span>// Arrow method = auto-bound</span>\n <span>increment</span> = () =&gt; {\n <span>this</span>.<span>setState</span>((<span>prev</span>) =&gt; ({\n <span>count</span>: <span>prev</span>.<span>count</span> + <span>1</span>\n }))\n }\n\n <span>componentDidMount</span>() {\n <span>document</span>.<span>title</span> = <span>`Count: ${this.state.count}`</span>\n }\n\n <span>componentDidUpdate</span>(<span>prevProps</span>, <span>prevState</span>) {\n <span>if</span> (<span>prevState</span>.<span>count</span> !== <span>this</span>.<span>state</span>.<span>count</span>) {\n <span>document</span>.<span>title</span> = <span>`Count: ${this.state.count}`</span>\n }\n }\n\n <span>componentWillUnmount</span>() {\n <span>document</span>.<span>title</span> = <span>'App'</span>\n }\n\n <span>render</span>() {\n <span>return</span> (\n &lt;<span>button</span> <span>onClick</span>=<span>{this.increment}</span>&gt;\n {<span>this</span>.<span>state</span>.<span>count</span>}\n &lt;/<span>button</span>&gt;\n )\n }\n}</pre></div>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<div class=\"code-dots\"><div class=\"code-dot tone-danger\"></div><div class=\"code-dot tone-tip\"></div><div class=\"code-dot tone-success\"></div></div>\n<span class=\"code-filename\">Error Boundary (class required)</span>\n<span class=\"code-lang\">JSX</span>\n</div>\n<div class=\"code-body\"><pre><span>class</span> <span>ErrorBoundary</span> <span>extends</span> <span>React.Component</span> {\n <span>state</span> = { <span>hasError</span>: <span>false</span>, <span>error</span>: <span>null</span> }\n\n <span>static</span> <span>getDerivedStateFromError</span>(<span>error</span>) {\n <span>return</span> { <span>hasError</span>: <span>true</span>, <span>error</span> }\n }\n\n <span>componentDidCatch</span>(<span>error</span>, <span>info</span>) {\n <span>logErrorToService</span>(<span>error</span>, <span>info</span>.<span>componentStack</span>)\n }\n\n <span>render</span>() {\n <span>if</span> (<span>this</span>.<span>state</span>.<span>hasError</span>) {\n <span>return</span> (\n &lt;<span>div</span>&gt;\n &lt;<span>h2</span>&gt;Something went wrong&lt;/<span>h2</span>&gt;\n &lt;<span>button</span> <span>onClick</span>=<span>{() =&gt;</span>\n <span>this</span>.<span>setState</span>({ <span>hasError</span>: <span>false</span> })\n }&gt;Retry&lt;/<span>button</span>&gt;\n &lt;/<span>div</span>&gt;\n )\n }\n <span>return this</span>.<span>props</span>.<span>children</span>\n }\n}\n\n<span>// Usage:</span>\n&lt;<span>ErrorBoundary</span>&gt;\n &lt;<span>RiskyComponent</span> /&gt;\n&lt;/<span>ErrorBoundary</span>&gt;</pre></div>\n</div>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<div class=\"code-dots\"><div class=\"code-dot tone-danger\"></div><div class=\"code-dot tone-tip\"></div><div class=\"code-dot tone-success\"></div></div>\n<span class=\"code-filename\">ES6 Classes \u2014 Core Concepts</span>\n<span class=\"code-lang\">JS</span>\n</div>\n<div class=\"code-body\"><pre><span>// Inheritance</span>\n<span>class</span> <span>Animal</span> {\n <span>constructor</span>(<span>name</span>) { <span>this</span>.<span>name</span> = <span>name</span> }\n <span>speak</span>() { <span>return</span> <span>`${this.name} makes a noise`</span> }\n <span>static</span> <span>create</span>(<span>name</span>) { <span>return new</span> <span>this</span>(<span>name</span>) } <span>// static factory</span>\n}\n\n<span>class</span> <span>Dog</span> <span>extends</span> <span>Animal</span> {\n <span>constructor</span>(<span>name</span>, <span>breed</span>) {\n <span>super</span>(<span>name</span>) <span>// must call super() before using this</span>\n <span>this</span>.<span>breed</span> = <span>breed</span>\n }\n <span>speak</span>() { <span>return</span> <span>`${this.name} barks`</span> } <span>// override</span>\n}\n\n<span>// Private fields (ES2022)</span>\n<span>class</span> <span>Store</span> {\n #<span>state</span> = {} <span>// truly private, no _convention</span>\n <span>get</span> (<span>key</span>) { <span>return</span> <span>this</span>.#<span>state</span>[<span>key</span>] }\n <span>set</span> (<span>key</span>, <span>val</span>) { <span>this</span>.#<span>state</span>[<span>key</span>] = <span>val</span> }\n}\n\n<span>// Getters &amp; setters</span>\n<span>class</span> <span>Circle</span> {\n <span>constructor</span>(<span>r</span>) { <span>this</span>.#<span>r</span> = <span>r</span> }\n #<span>r</span> = <span>0</span>\n <span>get</span> <span>area</span>() { <span>return</span> <span>Math</span>.<span>PI</span> * <span>this</span>.#<span>r</span> ** <span>2</span> } <span>// circle.area</span>\n <span>get</span> <span>radius</span>() { <span>return</span> <span>this</span>.#<span>r</span> }\n <span>set</span> <span>radius</span>(<span>r</span>) {\n <span>if</span> (<span>r</span> &lt; <span>0</span>) <span>throw</span> <span>new</span> <span>Error</span>(<span>'Negative radius'</span>)\n <span>this</span>.#<span>r</span> = <span>r</span>\n }\n}</pre></div>\n</div>\n</section>\n<section id=\"immutability\">\n<div class=\"section-header\">\n<div class=\"section-num\">15</div>\n<div class=\"section-title-group\">\n<h2>Immutability <span>Patterns</span></h2>\n<p>Never mutate state directly \u2014 every pattern for updating arrays and objects the React way</p>\n</div>\n</div>\n<div class=\"callout tone-danger\">\n<div class=\"callout-icon\"></div>\n<div class=\"callout-body\">\n<h4>Why Mutation Breaks React</h4>\n<p>React compares previous and next state <em>by reference</em>. If you mutate an object or array in place (<code>arr.push()</code>, <code>obj.name = 'x'</code>), the reference doesn't change \u2014 React thinks nothing changed and won't re-render. Always return a new object/array.</p>\n</div>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<div class=\"code-dots\"><div class=\"code-dot tone-danger\"></div><div class=\"code-dot tone-tip\"></div><div class=\"code-dot tone-success\"></div></div>\n<span class=\"code-filename\">immutable-state-patterns.js</span>\n<span class=\"code-lang\">JS</span>\n</div>\n<div class=\"code-body\"><pre><span>// \u2500\u2500\u2500 ARRAY OPERATIONS (immutable) \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n\n<span>// Add to end</span>\n<span>setItems</span>(<span>prev</span> =&gt; [...<span>prev</span>, <span>newItem</span>])\n\n<span>// Add to beginning</span>\n<span>setItems</span>(<span>prev</span> =&gt; [<span>newItem</span>, ...<span>prev</span>])\n\n<span>// Insert at index</span>\n<span>setItems</span>(<span>prev</span> =&gt; [\n ...<span>prev</span>.<span>slice</span>(<span>0</span>, <span>index</span>),\n <span>newItem</span>,\n ...<span>prev</span>.<span>slice</span>(<span>index</span>)\n])\n\n<span>// Remove by index</span>\n<span>setItems</span>(<span>prev</span> =&gt; <span>prev</span>.<span>filter</span>((<span>_</span>, <span>i</span>) =&gt; <span>i</span> !== <span>index</span>))\n\n<span>// Remove by id</span>\n<span>setItems</span>(<span>prev</span> =&gt; <span>prev</span>.<span>filter</span>(<span>item</span> =&gt; <span>item</span>.<span>id</span> !== <span>targetId</span>))\n\n<span>// Update item by id</span>\n<span>setItems</span>(<span>prev</span> =&gt; <span>prev</span>.<span>map</span>(<span>item</span> =&gt;\n <span>item</span>.<span>id</span> === <span>id</span> ? { ...<span>item</span>, ...<span>changes</span> } : <span>item</span>\n))\n\n<span>// Replace at index</span>\n<span>setItems</span>(<span>prev</span> =&gt; <span>prev</span>.<span>map</span>((<span>item</span>, <span>i</span>) =&gt; <span>i</span> === <span>index</span> ? <span>newItem</span> : <span>item</span>))\n\n<span>// Toggle boolean on item</span>\n<span>setTodos</span>(<span>prev</span> =&gt; <span>prev</span>.<span>map</span>(<span>t</span> =&gt;\n <span>t</span>.<span>id</span> === <span>id</span> ? { ...<span>t</span>, <span>done</span>: !<span>t</span>.<span>done</span> } : <span>t</span>\n))\n\n<span>// Sort (must copy first)</span>\n<span>setItems</span>(<span>prev</span> =&gt; [...<span>prev</span>].<span>sort</span>((<span>a</span>, <span>b</span>) =&gt; <span>a</span>.<span>name</span>.<span>localeCompare</span>(<span>b</span>.<span>name</span>)))\n\n<span>// \u2500\u2500\u2500 OBJECT OPERATIONS (immutable) \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n\n<span>// Update top-level field</span>\n<span>setUser</span>(<span>prev</span> =&gt; ({ ...<span>prev</span>, <span>name</span>: <span>'Alice'</span> }))\n\n<span>// Update nested field (spread at each level)</span>\n<span>setUser</span>(<span>prev</span> =&gt; ({\n ...<span>prev</span>,\n <span>address</span>: { ...<span>prev</span>.<span>address</span>, <span>city</span>: <span>'Paris'</span> }\n}))\n\n<span>// Delete a key</span>\n<span>setData</span>((<span>prev</span>) =&gt; {\n <span>const</span> { [<span>keyToDelete</span>]: <span>_</span>, ...<span>rest</span> } = <span>prev</span>\n <span>return</span> <span>rest</span>\n})\n\n<span>// Add/update dynamic key</span>\n<span>setErrors</span>(<span>prev</span> =&gt; ({ ...<span>prev</span>, [<span>fieldName</span>]: <span>'Required'</span> }))\n\n<span>// \u2500\u2500\u2500 useReducer for complex immutable updates \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span>const</span> <span>reducer</span> = (<span>state</span>, <span>action</span>) =&gt; {\n <span>switch</span> (<span>action</span>.<span>type</span>) {\n <span>case</span> <span>'ADD'</span>: <span>return</span> { ...<span>state</span>, <span>items</span>: [...<span>state</span>.<span>items</span>, <span>action</span>.<span>payload</span>] }\n <span>case</span> <span>'REMOVE'</span>: <span>return</span> { ...<span>state</span>, <span>items</span>: <span>state</span>.<span>items</span>.<span>filter</span>(<span>i</span> =&gt; <span>i</span>.<span>id</span> !== <span>action</span>.<span>payload</span>) }\n <span>default</span>: <span>return</span> <span>state</span>\n }\n}</pre></div>\n</div>\n</section>\n<section id=\"error-handling\">\n<div class=\"section-header\">\n<div class=\"section-num\">16</div>\n<div class=\"section-title-group\">\n<h2>Error <span class=\"tone-info\">Handling</span></h2>\n<p>try/catch, custom Error classes, error boundaries, and resilient async patterns</p>\n</div>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<div class=\"code-dots\"><div class=\"code-dot tone-danger\"></div><div class=\"code-dot tone-tip\"></div><div class=\"code-dot tone-success\"></div></div>\n<span class=\"code-filename\">error-handling.js</span>\n<span class=\"code-lang\">JS</span>\n</div>\n<div class=\"code-body\"><pre><span>// \u2500\u2500\u2500 try / catch / finally \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span>try</span> {\n <span>const</span> <span>data</span> = <span>await</span> <span>fetchData</span>()\n <span>setData</span>(<span>data</span>)\n} <span>catch</span> (<span>err</span>) {\n <span>if</span> (<span>err</span> <span>instanceof</span> <span>NetworkError</span>) {\n <span>setError</span>(<span>'Connection failed. Please retry.'</span>)\n } <span>else if</span> (<span>err</span> <span>instanceof</span> <span>ValidationError</span>) {\n <span>setErrors</span>(<span>err</span>.<span>fields</span>)\n } <span>else</span> {\n <span>setError</span>(<span>err</span>.<span>message</span> ?? <span>'An unexpected error occurred'</span>)\n }\n} <span>finally</span> {\n <span>setLoading</span>(<span>false</span>) <span>// always runs</span>\n}\n\n<span>// \u2500\u2500\u2500 Custom Error classes \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span>class</span> <span>ApiError</span> <span>extends</span> <span>Error</span> {\n <span>constructor</span>(<span>message</span>, <span>status</span>, <span>data</span> = {}) {\n <span>super</span>(<span>message</span>)\n <span>this</span>.<span>name</span> = <span>'ApiError'</span>\n <span>this</span>.<span>status</span> = <span>status</span>\n <span>this</span>.<span>data</span> = <span>data</span>\n }\n}\n\n<span>class</span> <span>ValidationError</span> <span>extends</span> <span>Error</span> {\n <span>constructor</span>(<span>fields</span>) {\n <span>super</span>(<span>'Validation failed'</span>)\n <span>this</span>.<span>name</span> = <span>'ValidationError'</span>\n <span>this</span>.<span>fields</span> = <span>fields</span>\n }\n}\n\n<span>// Throw in fetch utility</span>\n<span>if</span> (!<span>res</span>.<span>ok</span>) <span>throw new</span> <span>ApiError</span>(<span>'Not found'</span>, <span>res</span>.<span>status</span>)\n\n<span>// \u2500\u2500\u2500 Result pattern (no throw) \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span>const</span> <span>safeAsync</span> = <span>async</span> (<span>fn</span>) =&gt; {\n <span>try</span> {\n <span>const</span> <span>data</span> = <span>await</span> <span>fn</span>()\n <span>return</span> [<span>data</span>, <span>null</span>]\n } <span>catch</span> (<span>err</span>) {\n <span>return</span> [<span>null</span>, <span>err</span>]\n }\n}\n\n<span>// Usage \u2014 no try/catch needed at call site</span>\n<span>const</span> [<span>user</span>, <span>error</span>] = <span>await</span> <span>safeAsync</span>(() =&gt; <span>fetchUser</span>(<span>id</span>))\n<span>if</span> (<span>error</span>) <span>setError</span>(<span>error</span>.<span>message</span>)\n<span>else</span> <span>setUser</span>(<span>user</span>)\n\n<span>// \u2500\u2500\u2500 Global error handler \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span>window</span>.<span>addEventListener</span>(<span>'unhandledrejection'</span>, (<span>event</span>) =&gt; {\n <span>console</span>.<span>error</span>(<span>'Unhandled Promise rejection:'</span>, <span>event</span>.<span>reason</span>)\n <span>sendToSentry</span>(<span>event</span>.<span>reason</span>)\n})</pre></div>\n</div>\n</section>\n<section id=\"jsx-js\">\n<div class=\"section-header\">\n<div class=\"section-num\">17</div>\n<div class=\"section-title-group\">\n<h2>JavaScript <span class=\"tone-info\">Patterns in JSX</span></h2>\n<p>The JavaScript expressions, patterns, and idioms that appear most in React component code</p>\n</div>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<div class=\"code-dots\"><div class=\"code-dot tone-danger\"></div><div class=\"code-dot tone-tip\"></div><div class=\"code-dot tone-success\"></div></div>\n<span class=\"code-filename\">jsx-patterns.jsx</span>\n<span class=\"code-lang\">JSX</span>\n</div>\n<div class=\"code-body\"><pre><span>// \u2500\u2500\u2500 Dynamic className \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span>// Template literal (simple)</span>\n&lt;<span>div</span> <span>className</span>=<span>{`card ${isActive ? 'card--active' : ''} ${variant}`}</span>&gt;\n\n<span>// Array + join (complex)</span>\n<span>const</span> <span>classes</span> = [\n <span>'card'</span>,\n <span>isActive</span> &amp;&amp; <span>'card--active'</span>,\n <span>isLarge</span> &amp;&amp; <span>'card--large'</span>,\n <span>variant</span> &amp;&amp; <span>`card--${variant}`</span>,\n].<span>filter</span>(<span>Boolean</span>).<span>join</span>(<span>' '</span>)\n<span>// or use the `clsx` library: clsx('card', { 'card--active': isActive })</span>\n\n<span>// \u2500\u2500\u2500 Dynamic styles \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n&lt;<span>div</span> <span>style</span>=<span>{{</span>\n <span>color</span>: <span>theme</span> === <span>'dark'</span> ? <span>'#fff'</span> : <span>'#000'</span>,\n <span>opacity</span>: <span>isVisible</span> ? <span>1</span> : <span>0</span>,\n <span>transform</span>: <span>`translateX(${offset}px)`</span>,\n}}&gt;\n\n<span>// \u2500\u2500\u2500 IIFE in JSX (complex multi-branch) \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n{(() =&gt; {\n <span>if</span> (<span>isLoading</span>) <span>return</span> &lt;<span>Spinner</span> /&gt;\n <span>if</span> (<span>error</span>) <span>return</span> &lt;<span>Error</span> /&gt;\n <span>return</span> &lt;<span>Content</span> /&gt;\n})()}\n\n<span>// \u2500\u2500\u2500 JSX spread props \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span>const</span> <span>buttonProps</span> = { <span>onClick</span>: <span>handleClick</span>, <span>disabled</span>: <span>isLoading</span>, <span>type</span>: <span>'submit'</span> }\n&lt;<span>Button</span> {...<span>buttonProps</span>} /&gt;\n\n<span>// \u2500\u2500\u2500 Component as value \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span>const</span> <span>icons</span> = { success: &lt;<span>CheckIcon</span> /&gt;, error: &lt;<span>XIcon</span> /&gt;, info: &lt;<span>InfoIcon</span> /&gt; }\n{<span>icons</span>[<span>status</span>]}\n\n<span>// \u2500\u2500\u2500 Render functions (components via function) \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span>const</span> <span>renderItem</span> = (<span>item</span>, <span>index</span>) =&gt; (\n &lt;<span>li</span> <span>key</span>=<span>{item.id}</span> <span>data-index</span>=<span>{index}</span>&gt;{<span>item</span>.<span>name</span>}&lt;/<span>li</span>&gt;\n)\n&lt;<span>ul</span>&gt;{<span>items</span>.<span>map</span>(<span>renderItem</span>)}&lt;/<span>ul</span>&gt;\n\n<span>// \u2500\u2500\u2500 Fragment shorthand \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span>return</span> (\n &lt;&gt;\n &lt;<span>Header</span> /&gt;\n &lt;<span>Main</span> /&gt;\n &lt;<span>Footer</span> /&gt;\n &lt;/&gt;\n)\n\n<span>// \u2500\u2500\u2500 Keys in map \u2014 do's and don'ts \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span>// Stable, unique id from data</span>\n<span>items</span>.<span>map</span>(<span>item</span> =&gt; &lt;<span>Item</span> <span>key</span>=<span>{item.id}</span> /&gt;)\n<span>// Index as key when items can reorder/delete</span>\n<span>items</span>.<span>map</span>((<span>item</span>, <span>i</span>) =&gt; &lt;<span>Item</span> <span>key</span>=<span>{i}</span> /&gt;) <span>// </span>\n<span>// Index is fine for static lists</span>\n<span>staticSteps</span>.<span>map</span>((<span>s</span>, <span>i</span>) =&gt; &lt;<span>Step</span> <span>key</span>=<span>{i}</span> /&gt;) <span>// </span></pre></div>\n</div>\n</section>\n<section id=\"type-coercion\">\n<div class=\"section-header\">\n<div class=\"section-num\">18</div>\n<div class=\"section-title-group\">\n<h2>Type Coercion <span class=\"tone-tip\">Traps</span></h2>\n<p>JavaScript's implicit conversions that bite React developers \u2014 and how to dodge them</p>\n</div>\n</div>\n<div class=\"comparison-table\">\n<table class=\"comparison-table\">\n<thead><tr><th>Expression</th><th>Result</th><th>Why / Notes</th></tr></thead>\n<tbody>\n<tr><td><code>0 &amp;&amp; &lt;X /&gt;</code></td><td><code>\"0\"</code> in DOM</td><td>0 is falsy but not a boolean \u2014 renders as text node</td></tr>\n<tr><td><code>'' === false</code></td><td><code>false</code></td><td>Use <code>===</code> always \u2014 strict equality, no coercion</td></tr>\n<tr><td><code>null == undefined</code></td><td><code>true</code></td><td>The one useful case of <code>==</code> \u2014 nullish check</td></tr>\n<tr><td><code>[] == false</code></td><td><code>true</code></td><td>Array coerces to \"\" which coerces to 0 which equals 0</td></tr>\n<tr><td><code>[] + {}</code></td><td><code>\"[object Object]\"</code></td><td>Classic \u2014 never add arrays/objects</td></tr>\n<tr><td><code>NaN === NaN</code></td><td><code>false</code></td><td>Use <code>Number.isNaN()</code> to check for NaN</td></tr>\n<tr><td><code>typeof null</code></td><td><code>\"object\"</code></td><td>Historical bug \u2014 use <code>=== null</code> check instead</td></tr>\n<tr><td><code>parseInt('8px')</code></td><td><code>8</code></td><td>Parses until non-numeric \u2014 use for CSS value extraction</td></tr>\n<tr><td><code>+'3'</code></td><td><code>3</code></td><td>Unary + coerces to number \u2014 useful but cryptic</td></tr>\n<tr><td><code>!!value</code></td><td><code>true/false</code></td><td>Double-negate = coerce to boolean \u2014 safe in JSX</td></tr>\n</tbody>\n</table>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<div class=\"code-dots\"><div class=\"code-dot tone-danger\"></div><div class=\"code-dot tone-tip\"></div><div class=\"code-dot tone-success\"></div></div>\n<span class=\"code-filename\">type-safety-in-react.js</span>\n<span class=\"code-lang\">JS</span>\n</div>\n<div class=\"code-body\"><pre><span>// \u2500\u2500\u2500 Truthy / Falsy values \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span>// FALSY: false, 0, -0, 0n, '', null, undefined, NaN</span>\n<span>// TRUTHY: everything else \u2014 including [], {}, '0', 'false'</span>\n\n<span>// \u2500\u2500\u2500 Safe type checks \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span>typeof</span> <span>value</span> === <span>'string'</span> <span>// string check</span>\n<span>typeof</span> <span>fn</span> === <span>'function'</span> <span>// function check (callbacks)</span>\n<span>Array</span>.<span>isArray</span>(<span>value</span>) <span>// not typeof 'object'!</span>\n<span>value</span> === <span>null</span> <span>// exact null check</span>\n<span>value</span> == <span>null</span> <span>// null OR undefined (safe use of ==)</span>\n<span>Number</span>.<span>isNaN</span>(<span>value</span>) <span>// NOT isNaN() which coerces first</span>\n<span>Number</span>.<span>isFinite</span>(<span>value</span>) <span>// excludes Infinity and NaN</span>\n<span>Number</span>.<span>isInteger</span>(<span>value</span>) <span>// whole number check</span>\n\n<span>// \u2500\u2500\u2500 String \u2194 Number conversions \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span>Number</span>(<span>'42'</span>) <span>// 42 (strict \u2014 NaN if invalid)</span>\n<span>parseInt</span>(<span>'42px'</span>) <span>// 42 (parses until invalid char)</span>\n<span>parseFloat</span>(<span>'3.14em'</span>) <span>// 3.14</span>\n<span>String</span>(<span>42</span>) <span>// '42'</span>\n(<span>42</span>).<span>toString</span>() <span>// '42'</span>\n\n<span>// \u2500\u2500\u2500 Equality in React \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span>// Always use === (strict equality)</span>\n<span>status</span> === <span>'loading'</span> <span>// </span>\n<span>count</span> === <span>0</span> <span>// </span>\n<span>user</span> === <span>null</span> <span>// </span>\n\n<span>// \u2500\u2500\u2500 Object equality is by reference! \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span>const</span> <span>a</span> = { <span>x</span>: <span>1</span> }\n<span>const</span> <span>b</span> = { <span>x</span>: <span>1</span> }\n<span>a</span> === <span>b</span> <span>// false \u2014 different references</span>\n<span>// This is why React compares state by reference and why mutation breaks re-renders</span>\n\n<span>// Deep comparison (don't use in React renders \u2014 use useMemo/useCallback)</span>\n<span>JSON</span>.<span>stringify</span>(<span>a</span>) === <span>JSON</span>.<span>stringify</span>(<span>b</span>) <span>// true (slow, but simple)</span></pre></div>\n</div>\n</section>\n<section id=\"advanced-patterns\">\n<div class=\"section-header\">\n<div class=\"section-num\">19</div>\n<div class=\"section-title-group\">\n<h2>Advanced <span class=\"tone-info\">Patterns</span></h2>\n<p>Currying, memoization, composition, generators \u2014 the techniques that elevate React code to senior level</p>\n</div>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<div class=\"code-dots\"><div class=\"code-dot tone-danger\"></div><div class=\"code-dot tone-tip\"></div><div class=\"code-dot tone-success\"></div></div>\n<span class=\"code-filename\">advanced-patterns.js</span>\n<span class=\"code-lang\">JS</span>\n</div>\n<div class=\"code-body\"><pre><span>// \u2500\u2500\u2500 Currying \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span>// Function that returns a function \u2014 pre-fill arguments</span>\n<span>const</span> <span>multiply</span> = (<span>factor</span>) =&gt; (<span>number</span>) =&gt; <span>number</span> * <span>factor</span>\n<span>const</span> <span>double</span> = <span>multiply</span>(<span>2</span>) <span>// double(5) \u2192 10</span>\n<span>const</span> <span>triple</span> = <span>multiply</span>(<span>3</span>) <span>// triple(5) \u2192 15</span>\n\n<span>// Real React use: event handlers with data</span>\n<span>const</span> <span>handleFieldChange</span> = (<span>fieldName</span>) =&gt; (<span>e</span>) =&gt;\n <span>setForm</span>(<span>prev</span> =&gt; ({ ...<span>prev</span>, [<span>fieldName</span>]: <span>e</span>.<span>target</span>.<span>value</span> }))\n\n&lt;<span>input</span> <span>onChange</span>=<span>{handleFieldChange('email')}</span> /&gt; <span>// no inline arrow needed</span>\n&lt;<span>input</span> <span>onChange</span>=<span>{handleFieldChange('username')}</span> /&gt;\n\n<span>// \u2500\u2500\u2500 Memoization \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span>function</span> <span>memoize</span>(<span>fn</span>) {\n <span>const</span> <span>cache</span> = <span>new</span> <span>Map</span>()\n <span>return</span> (...<span>args</span>) =&gt; {\n <span>const</span> <span>key</span> = <span>JSON</span>.<span>stringify</span>(<span>args</span>)\n <span>if</span> (<span>cache</span>.<span>has</span>(<span>key</span>)) <span>return</span> <span>cache</span>.<span>get</span>(<span>key</span>)\n <span>const</span> <span>result</span> = <span>fn</span>(...<span>args</span>)\n <span>cache</span>.<span>set</span>(<span>key</span>, <span>result</span>)\n <span>return</span> <span>result</span>\n }\n}\n<span>// React has built-in: useMemo, useCallback, memo()</span>\n\n<span>// \u2500\u2500\u2500 Function composition \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span>const</span> <span>compose</span> = (...<span>fns</span>) =&gt; (<span>x</span>) =&gt; <span>fns</span>.<span>reduceRight</span>((<span>v</span>, <span>f</span>) =&gt; <span>f</span>(<span>v</span>), <span>x</span>)\n<span>const</span> <span>pipe</span> = (...<span>fns</span>) =&gt; (<span>x</span>) =&gt; <span>fns</span>.<span>reduce</span>((<span>v</span>, <span>f</span>) =&gt; <span>f</span>(<span>v</span>), <span>x</span>)\n\n<span>const</span> <span>processUser</span> = <span>pipe</span>(\n <span>trimFields</span>,\n <span>normalizeEmail</span>,\n <span>validateSchema</span>,\n <span>sanitizeHtml</span>\n)\n\n<span>// \u2500\u2500\u2500 Singleton pattern (global stores) \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span>let</span> <span>instance</span> = <span>null</span>\n<span>function</span> <span>getStore</span>() {\n <span>if</span> (!<span>instance</span>) <span>instance</span> = <span>createStore</span>()\n <span>return</span> <span>instance</span>\n}\n\n<span>// \u2500\u2500\u2500 Generator functions \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span>function</span>* <span>idGenerator</span>() {\n <span>let</span> <span>id</span> = <span>1</span>\n <span>while</span> (<span>true</span>) <span>yield</span> <span>id</span>++\n}\n<span>const</span> <span>nextId</span> = <span>idGenerator</span>()\n<span>nextId</span>.<span>next</span>().<span>value</span> <span>// 1</span>\n<span>nextId</span>.<span>next</span>().<span>value</span> <span>// 2</span>\n\n<span>// \u2500\u2500\u2500 Proxy for reactive objects \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span>const</span> <span>reactive</span> = (<span>obj</span>, <span>onChange</span>) =&gt; <span>new</span> <span>Proxy</span>(<span>obj</span>, {\n <span>set</span>(<span>target</span>, <span>key</span>, <span>value</span>) {\n <span>target</span>[<span>key</span>] = <span>value</span>\n <span>onChange</span>(<span>key</span>, <span>value</span>)\n <span>return</span> <span>true</span>\n }\n})</pre></div>\n</div>\n</section>\n<section id=\"tips-tricks\">\n<div class=\"section-header\">\n<div class=\"section-num\">20</div>\n<div class=\"section-title-group\">\n<h2>Tips, Tricks <span>&amp; Gotchas</span></h2>\n<p>The hard-won JavaScript wisdom every React developer accumulates over time \u2014 condensed</p>\n</div>\n</div>\n<div>\n<div class=\"tip-box\">\n<div class=\"tip-label\"> Destructure at boundary</div>\n<p>Destructure props at the function signature, not inside the body. It's the React community standard and makes the component's interface visible at a glance.</p>\n</div>\n<div class=\"tip-box tone-info\">\n<div class=\"tip-label\"> Short-circuit evaluation</div>\n<p><code>a &amp;&amp; b</code> returns <code>b</code> if <code>a</code> is truthy, else <code>a</code>. <code>a || b</code> returns <code>a</code> if truthy, else <code>b</code>. These aren't booleans \u2014 they return the actual values.</p>\n</div>\n<div class=\"tip-box tone-info\">\n<div class=\"tip-label\"> Object shorthand methods</div>\n<p><code>{'{ greet() { return \"hi\" } }'}</code> is shorthand for <code>{'{ greet: function() {...} }'}</code>. Shorter, but don't use arrow functions as object methods if you need <code>this</code>.</p>\n</div>\n<div class=\"tip-box tone-tip\">\n<div class=\"tip-label\"> map() needs return</div>\n<p>Arrow functions with <code>{'{}'}</code> braces need an explicit <code>return</code>. Omitting it gives <code>undefined</code>: <code>items.map(i =&gt; {'{ i.name }'})</code> \u2192 <code>[undefined, ...]</code>.</p>\n</div>\n<div class=\"tip-box tone-danger\">\n<div class=\"tip-label\"> Avoid object in deps</div>\n<p>Don't put object/array literals in <code>useEffect</code> deps: <code>useEffect(() =&gt; {}, [{'{}'}])</code> \u2014 every render creates a new reference, causing infinite loops. Use primitives or <code>useMemo</code>.</p>\n</div>\n<div class=\"tip-box\">\n<div class=\"tip-label\"> Chaining optional calls</div>\n<p><code>arr?.map(fn)?.filter(pred)</code> \u2014 chain optional calls safely. If <code>arr</code> is null, the entire chain short-circuits to <code>undefined</code>.</p>\n</div>\n<div class=\"tip-box tone-info\">\n<div class=\"tip-label\"> console tricks</div>\n<p><code>console.table(array)</code> renders arrays as tables. <code>console.group('label')</code> groups logs. <code>console.time('label') / timeEnd('label')</code> measures timing. <code>console.dir(elem)</code> inspects DOM.</p>\n</div>\n<div class=\"tip-box tone-info\">\n<div class=\"tip-label\"> Object spread order</div>\n<p>Later keys override earlier ones: <code>{'{ ...defaults, ...overrides }'}</code>. Put your overrides last. If you want some keys to be un-overridable, put them last instead.</p>\n</div>\n<div class=\"tip-box tone-tip\">\n<div class=\"tip-label\"> Array.from for ranges</div>\n<p><code>Array.from({'{ length: 5 }'}, (_, i) =&gt; i + 1)</code> creates <code>[1,2,3,4,5]</code>. Render <code>n</code> skeleton cards: <code>Array.from({'{ length: n }'})</code> then <code>.map()</code>.</p>\n</div>\n<div class=\"tip-box tone-success\">\n<div class=\"tip-label\"> Filter(Boolean) pattern</div>\n<p><code>['a', null, 'b', undefined, 'c'].filter(Boolean)</code> \u2192 <code>['a', 'b', 'c']</code>. Removes all falsy values. Pair with dynamic class arrays or conditional item arrays.</p>\n</div>\n<div class=\"tip-box\">\n<div class=\"tip-label\"> Computed keys in setState</div>\n<p><code>setState(prev =&gt; ({'{ ...prev, [fieldName]: value }'})</code> \u2014 computed property name <code>[fieldName]</code> lets one handler update any field by name. Powers generic form handlers.</p>\n</div>\n<div class=\"tip-box tone-danger\">\n<div class=\"tip-label\"> JSON.parse dangers</div>\n<p>Always wrap <code>JSON.parse</code> in <code>try/catch</code> \u2014 invalid JSON throws synchronously. Same for localStorage reads: users can corrupt stored data.</p>\n</div>\n</div>\n<div class=\"divider\">\n<div class=\"divider-line\"></div>\n<div class=\"divider-text\">// Performance Tips</div>\n<div class=\"divider-line\"></div>\n</div>\n<div class=\"step-list\">\n<div class=\"step\">\n<div class=\"step-num\">1</div>\n<div class=\"step-content\">\n<h4>Avoid Creating Functions/Objects in JSX</h4>\n<p>Every render creates new references for inline functions: <code>onClick={'{ () =&gt; fn() }'}</code> and inline objects: <code>style={'{{ color: \"red\" }}'}</code>. For expensive child components, move them outside JSX or use <code>useCallback</code> / <code>useMemo</code> to stabilize references. Stable references prevent unnecessary re-renders of memoized children.</p>\n</div>\n</div>\n<div class=\"step\">\n<div class=\"step-num\">2</div>\n<div class=\"step-content\">\n<h4>Lazy Initialization for Expensive useState</h4>\n<p>If the initial state requires a complex computation, pass a function to <code>useState</code>: <code>const [s, setS] = useState(() =&gt; expensiveCompute())</code>. The function runs only once on mount, not on every render. Without the function, <code>expensiveCompute()</code> would run every render even though only the first result is used.</p>\n</div>\n</div>\n<div class=\"step\">\n<div class=\"step-num\">3</div>\n<div class=\"step-content\">\n<h4>Prefer Map/Object Lookups Over Switch</h4>\n<p>A switch or if/else chain is O(n). A Map or object lookup is O(1). For routing components, status icons, theme tokens, and translation lookups, build a lookup object once and index into it: <code>const icon = ICON_MAP[status]</code>.</p>\n</div>\n</div>\n<div class=\"step\">\n<div class=\"step-num\">4</div>\n<div class=\"step-content\">\n<h4>Use structuredClone() for Deep Clones</h4>\n<p>The modern alternative to <code>JSON.parse(JSON.stringify(x))</code>: <code>structuredClone(obj)</code> handles Dates, Sets, Maps, and circular references, and is significantly faster. Available in all modern browsers and Node 17+.</p>\n</div>\n</div>\n<div class=\"step\">\n<div class=\"step-num\">5</div>\n<div class=\"step-content\">\n<h4>Batch State Updates (React 18+)</h4>\n<p>React 18 automatically batches all state updates \u2014 even inside <code>setTimeout</code>, Promises, and native event handlers \u2014 into a single re-render. In React 17 and below, only updates inside React event handlers were batched. You can opt out with <code>flushSync()</code> from <code>react-dom</code> when you need immediate DOM updates.</p>\n</div>\n</div>\n</div>\n</section>\n<section id=\"cheatsheet\">\n<div class=\"section-header\">\n<div class=\"section-num\">21</div>\n<div class=\"section-title-group\">\n<h2>Quick <span class=\"tone-info\">Cheatsheet</span></h2>\n<p>Everything on one page \u2014 bookmark and reference when coding</p>\n</div>\n</div>\n<div class=\"cheat-grid\">\n<div class=\"cheat-card\">\n<div class=\"cheat-card-header\">\n<span class=\"ch-icon\"></span><h4>Arrow Functions</h4>\n</div>\n<div class=\"code-body\"><pre><span>// Implicit return</span>\n<span>const</span> <span>add</span> = (<span>a</span>, <span>b</span>) =&gt; <span>a</span> + <span>b</span>\n<span>// Return object</span>\n<span>const</span> <span>make</span> = <span>n</span> =&gt; ({ <span>name</span>: <span>n</span> })\n<span>// Async</span>\n<span>const</span> <span>get</span> = <span>async</span> (<span>url</span>) =&gt; (<span>await</span> <span>fetch</span>(<span>url</span>)).<span>json</span>()</pre></div>\n</div>\n<div class=\"cheat-card\">\n<div class=\"cheat-card-header\">\n<span class=\"ch-icon\">{ }</span><h4>Destructuring</h4>\n</div>\n<div class=\"code-body\"><pre><span>const</span> { <span>a</span>, <span>b</span> = <span>0</span>, <span>c</span>: <span>alias</span> } = <span>obj</span>\n<span>const</span> [<span>x</span>, , <span>z</span>] = <span>arr</span>\n<span>// In params</span>\n<span>const</span> <span>fn</span> = ({ <span>name</span>, <span>age</span> = <span>0</span> }) =&gt; ...\n<span>// Rest</span>\n<span>const</span> { <span>id</span>, ...<span>rest</span> } = <span>obj</span></pre></div>\n</div>\n<div class=\"cheat-card\">\n<div class=\"cheat-card-header\">\n<span class=\"ch-icon\">...</span><h4>Spread</h4>\n</div>\n<div class=\"code-body\"><pre><span>// Array clone + extend</span>\n<span>const</span> <span>b</span> = [...<span>a</span>, <span>newItem</span>]\n<span>// Object clone + override</span>\n<span>const</span> <span>u</span> = { ...<span>user</span>, <span>age</span>: <span>31</span> }\n<span>// JSX props</span>\n&lt;<span>Btn</span> {...<span>props</span>} /&gt;</pre></div>\n</div>\n<div class=\"cheat-card\">\n<div class=\"cheat-card-header\">\n<span class=\"ch-icon\">[ ]</span><h4>Array Methods</h4>\n</div>\n<div class=\"code-body\"><pre><span>arr</span>.<span>map</span>(<span>fn</span>) <span>// transform</span>\n<span>arr</span>.<span>filter</span>(<span>fn</span>) <span>// keep matching</span>\n<span>arr</span>.<span>reduce</span>(<span>fn</span>,<span>0</span>) <span>// accumulate</span>\n<span>arr</span>.<span>find</span>(<span>fn</span>) <span>// first match</span>\n<span>arr</span>.<span>some</span>(<span>fn</span>) <span>// any match?</span>\n<span>arr</span>.<span>every</span>(<span>fn</span>) <span>// all match?</span>\n[...<span>arr</span>].<span>sort</span>(<span>fn</span>) <span>// sort (copy!)</span></pre></div>\n</div>\n<div class=\"cheat-card\">\n<div class=\"cheat-card-header\">\n<span class=\"ch-icon\">\u23f3</span><h4>Async Patterns</h4>\n</div>\n<div class=\"code-body\"><pre><span>// Sequential</span>\n<span>const</span> <span>a</span> = <span>await</span> <span>fetchA</span>()\n<span>const</span> <span>b</span> = <span>await</span> <span>fetchB</span>()\n<span>// Parallel</span>\n<span>const</span> [<span>a</span>, <span>b</span>] = <span>await</span> <span>Promise</span>.<span>all</span>([<span>fetchA</span>(), <span>fetchB</span>()])\n<span>// Settle all</span>\n<span>const</span> <span>res</span> = <span>await</span> <span>Promise</span>.<span>allSettled</span>([...])</pre></div>\n</div>\n<div class=\"cheat-card\">\n<div class=\"cheat-card-header\">\n<span class=\"ch-icon\"></span><h4>Error Handling</h4>\n</div>\n<div class=\"code-body\"><pre><span>try</span> {\n <span>const</span> <span>d</span> = <span>await</span> <span>fetch</span>(<span>url</span>)\n} <span>catch</span> (<span>err</span>) {\n <span>setError</span>(<span>err</span>.<span>message</span>)\n} <span>finally</span> {\n <span>setLoading</span>(<span>false</span>)\n}\n<span>// Result pattern</span>\n<span>const</span> [<span>d</span>, <span>e</span>] = <span>await</span> <span>safeAsync</span>(<span>fn</span>)</pre></div>\n</div>\n<div class=\"cheat-card\">\n<div class=\"cheat-card-header\">\n<span class=\"ch-icon\"></span><h4>Conditionals in JSX</h4>\n</div>\n<div class=\"code-body\"><pre><span>// &amp;&amp; short-circuit</span>\n{<span>show</span> &amp;&amp; &lt;<span>X</span> /&gt;}\n<span>// Ternary</span>\n{<span>ok</span> ? &lt;<span>A</span> /&gt; : &lt;<span>B</span> /&gt;}\n<span>// Early return</span>\n<span>if</span> (<span>loading</span>) <span>return</span> &lt;<span>Spin</span> /&gt;\n<span>// Object map</span>\n<span>const</span> <span>m</span> = { <span>a</span>: &lt;<span>A</span>/&gt;, <span>b</span>: &lt;<span>B</span>/&gt; }\n{<span>m</span>[<span>status</span>]}</pre></div>\n</div>\n<div class=\"cheat-card\">\n<div class=\"cheat-card-header\">\n<span class=\"ch-icon\"></span><h4>Object Methods</h4>\n</div>\n<div class=\"code-body\"><pre><span>Object</span>.<span>keys</span>(<span>o</span>) <span>// keys array</span>\n<span>Object</span>.<span>values</span>(<span>o</span>) <span>// values array</span>\n<span>Object</span>.<span>entries</span>(<span>o</span>) <span>// [k,v] pairs</span>\n<span>Object</span>.<span>fromEntries</span>(<span>a</span>) <span>// entries\u2192obj</span>\n<span>Object</span>.<span>hasOwn</span>(<span>o</span>,<span>'k'</span>) <span>// has key?</span>\n<span>structuredClone</span>(<span>o</span>) <span>// deep clone</span></pre></div>\n</div>\n<div class=\"cheat-card\">\n<div class=\"cheat-card-header\">\n<span class=\"ch-icon\">\u23f0</span><h4>Timers in useEffect</h4>\n</div>\n<div class=\"code-body\"><pre><span>useEffect</span>(() =&gt; {\n <span>const</span> <span>t</span> = <span>setTimeout</span>(<span>fn</span>, <span>300</span>)\n <span>return</span> () =&gt; <span>clearTimeout</span>(<span>t</span>)\n}, [<span>dep</span>])\n\n<span>useEffect</span>(() =&gt; {\n <span>const</span> <span>i</span> = <span>setInterval</span>(<span>fn</span>, <span>1000</span>)\n <span>return</span> () =&gt; <span>clearInterval</span>(<span>i</span>)\n}, [])</pre></div>\n</div>\n<div class=\"cheat-card\">\n<div class=\"cheat-card-header\">\n<span class=\"ch-icon\"></span><h4>String Methods</h4>\n</div>\n<div class=\"code-body\"><pre><span>'s'</span>.<span>includes</span>(<span>'x'</span>) <span>// bool</span>\n<span>'s'</span>.<span>startsWith</span>(<span>'x'</span>) <span>// bool</span>\n<span>'s'</span>.<span>split</span>(<span>','</span>) <span>// array</span>\n<span>'s'</span>.<span>trim</span>() <span>// trimmed</span>\n<span>'s'</span>.<span>replace</span>(<span>/r/g</span>,<span>'x'</span>) <span>// replace</span>\n<span>`${<span>val</span>}`</span> <span>// template</span></pre></div>\n</div>\n<div class=\"cheat-card\">\n<div class=\"cheat-card-header\">\n<span class=\"ch-icon\"></span><h4>Immutable State Updates</h4>\n</div>\n<div class=\"code-body\"><pre><span>// Add to array</span>\n<span>set</span>(<span>p</span> =&gt; [...<span>p</span>, <span>item</span>])\n<span>// Remove by id</span>\n<span>set</span>(<span>p</span> =&gt; <span>p</span>.<span>filter</span>(<span>i</span> =&gt; <span>i</span>.<span>id</span> !== <span>id</span>))\n<span>// Update field</span>\n<span>set</span>(<span>p</span> =&gt; ({ ...<span>p</span>, <span>name</span>: <span>'x'</span> }))\n<span>// Update in array</span>\n<span>set</span>(<span>p</span> =&gt; <span>p</span>.<span>map</span>(<span>i</span> =&gt; <span>i</span>.<span>id</span>===<span>id</span> ? {...<span>i</span>,...<span>c</span>} : <span>i</span>))</pre></div>\n</div>\n<div class=\"cheat-card\">\n<div class=\"cheat-card-header\">\n<span class=\"ch-icon\"></span><h4>Closures &amp; useEffect</h4>\n</div>\n<div class=\"code-body\"><pre><span>// Stale closure </span>\n<span>useEffect</span>(() =&gt; {\n <span>setInterval</span>(() =&gt; <span>set</span>(<span>count</span> + <span>1</span>), <span>1000</span>)\n}, [])\n\n<span>// Functional update </span>\n<span>useEffect</span>(() =&gt; {\n <span>const</span> <span>t</span> = <span>setInterval</span>(() =&gt; <span>set</span>(<span>p</span> =&gt; <span>p</span>+<span>1</span>), <span>1000</span>)\n <span>return</span> () =&gt; <span>clearInterval</span>(<span>t</span>)\n}, [])</pre></div>\n</div>\n</div>\n<div class=\"divider\">\n<div class=\"divider-line\"></div>\n<div class=\"divider-text\">// The Golden Rules of JavaScript in React</div>\n<div class=\"divider-line\"></div>\n</div>\n<div class=\"comparison-table\">\n<table class=\"comparison-table\">\n<thead><tr><th>Rule</th><th>Do</th><th>Don't</th></tr></thead>\n<tbody>\n<tr><td>Array mutation</td><td><code>[...arr, item]</code> / <code>filter()</code> / <code>map()</code></td><td><code>arr.push()</code> / <code>arr.splice()</code> / <code>arr[i] = x</code></td></tr>\n<tr><td>Object mutation</td><td><code>{'{ ...obj, key: val }'}</code></td><td><code>obj.key = val</code> then setState</td></tr>\n<tr><td>Sort</td><td><code>[...arr].sort(fn)</code></td><td><code>arr.sort(fn)</code> \u2014 mutates!</td></tr>\n<tr><td>Equality</td><td><code>===</code> strict always</td><td><code>==</code> except for null/undefined check</td></tr>\n<tr><td>Type check</td><td><code>Array.isArray()</code>, <code>typeof</code>, <code>=== null</code></td><td><code>typeof arr === 'object'</code> for arrays</td></tr>\n<tr><td>Async state</td><td>Functional update <code>setState(prev =&gt; ...)</code></td><td>Capture state in closure directly</td></tr>\n<tr><td>Timers</td><td>Store ID and <code>clearTimeout(id)</code> in cleanup</td><td>Forget to clear on unmount</td></tr>\n<tr><td>Fetch</td><td>AbortController + check AbortError</td><td>setState after unmount race conditions</td></tr>\n<tr><td>Keys in map()</td><td>Stable unique <code>id</code> from data</td><td>Array index for reorderable lists</td></tr>\n<tr><td>0 in JSX</td><td><code>count &gt; 0 &amp;&amp; &lt;X /&gt;</code> or <code>!!count &amp;&amp; &lt;X /&gt;</code></td><td><code>count &amp;&amp; &lt;X /&gt;</code> \u2014 renders \"0\" in DOM</td></tr>\n</tbody>\n</table>\n</div>\n</section>";

